DRUGS.push(

{id:11,n:"Теофілін",g:"Дихальна система",grp:"Ксантин / міотропний бронхолітик",
mech:"Похідний ксантину (спорідненість з кофеїном). Неселективне інгібування фосфодіестераз (ФДЕ III та IV) → цАМФ і цГМФ не розщеплюються → накопичуються → розслаблення гладкої мускулатури бронхів. Блокада аденозинових рецепторів (A1, A2). Стимуляція дихальної мускулатури (діафрагма). Протизапальна дія (пригнічення вивільнення медіаторів). Позитивний хронотропний та інотропний ефект.",
ind:"БА (в комбінованих схемах). Бронхообструктивний синдром при ХОЗЛ. Легенева гіпертензія. Cor pulmonale (легеневе серце). Апное у недоношених.",
side:"Нудота, блювота, диспепсія (найчастіші). Збудження, безсоння. Тахіаритмії. Судоми (при передозуванні). Гіпотензія. Вузький терапевтичний індекс!",
contra:"Епілепсія (знижує поріг судом). Тяжкі аритмії. Виразкова хвороба. Тяжка ниркова або печінкова недостатність. Гіпертиреоз.",
combo:"НЕБЕЗПЕЧНО: + ципрофлоксацин, кларитроміцин, еритроміцин (інгібітори CYP1A2 → рівень теофіліну ↑ → токсичність). Куріння ЗНИЖУЄ рівень теофіліну (індукція CYP1A2).",
chain:["Інгібування ФДЕ III та IV","цАМФ та цГМФ не розщеплюються → накопичуються","Протеїнкінази A та G активуються","Фосфорилювання MLCK → інактивація","Розслаблення гладкої мускулатури бронхів","Додатково: блокада аденозинових рецепторів → бронходилатація + стимуляція дихальних мʼязів"],
tip:"ВУЗЬКИЙ терапевтичний індекс! Контроль рівня в крові: 10-20 мкг/мл (нижче — неефект., вище — токсично). Ципрофлоксацин → підвищує токсичність! Куріння → знижує ефект.",
q:[
{type:"mcq",q:"Теофілін є похідним:",o:["Піримідину","Ксантину (спорідненість з кофеїном)","Пуринових нуклеотидів","Простагландинів"],a:1,ex:"Метилксантин — хімічна група, до якої належать теофілін, кофеїн, теобромін. Схожий механізм (інгібування ФДЕ) та побічні ефекти (збудження ЦНС)."},
{type:"mcq",q:"Основний механізм бронходилататорної дії теофіліну:",o:["Агонізм β2-рецепторів","Блокада М3-холінорецепторів","Інгібування ФДЕ → цАМФ↑","Антагонізм лейкотрієнових рецепторів"],a:2,ex:"Інгібування фосфодіестерази → цАМФ та цГМФ не розщеплюються → накопичуються → бронходилатація. Цей же механізм у кофеїну, але теофілін сильніший бронходилататор."},
{type:"mcq",q:"Терапевтичний рівень теофіліну в плазмі крові:",o:["1-5 мкг/мл","10-20 мкг/мл","30-50 мкг/мл","Понад 100 мкг/мл"],a:1,ex:"10-20 мкг/мл — терапевтичне вікно. До 10 мкг/мл — неефективний. Вище 20 мкг/мл — токсично (нудота, аритмії, судоми). ВУЗЬКИЙ терапевтичний індекс."},
{type:"mcq",q:"Взаємодія теофіліну з ципрофлоксацином:",o:["Ципрофлоксацин знижує рівень теофіліну","Ципрофлоксацин підвищує рівень теофіліну (інгібіція CYP1A2) → токсичність","Взаємодії немає","Обидва підвищуються"],a:1,ex:"Ципрофлоксацин — інгібітор CYP1A2 (ферменту метаболізму теофіліну). Підвищує концентрацію теофіліну → ризик токсичності (аритмії, судоми). При призначенні ципро — знизити дозу теофіліну."},
{type:"mcq",q:"Вплив куріння на рівень теофіліну:",o:["Підвищує рівень (куріння пригнічує метаболізм)","Знижує рівень (куріння індукує CYP1A2 → швидший метаболізм)","Не впливає","Подвоює токсичність"],a:1,ex:"Куріння (поліциклічні ароматичні вуглеводні) індукує CYP1A2 → прискорений метаболізм теофіліну → знижена концентрація. Курці потребують вищих доз. При відмові від куріння — знизити дозу!"},
{type:"case",scenario:"Пацієнт з БА приймає теофілін. Лікар призначив ципрофлоксацин з приводу інфекції сечових шляхів. Через 3 дні — нудота, серцебиття, тремор.",q:"Що відбулось?",o:["Алергія на ципрофлоксацин","Токсичність теофіліну (ципрофлоксацин → CYP1A2 ↓ → теофілін ↑)","Загострення БА","Побічний ефект ципрофлоксацину"],a:1,ex:"Класична взаємодія. Ципрофлоксацин інгібує CYP1A2 → концентрація теофіліну зростає → токсичність (нудота, тахікардія, тремор). Рішення: знизити дозу теофіліну або змінити АБ."},
{type:"mcq",q:"Теофілін при апное недоношених дітей діє через:",o:["Пригнічення дихального центру","Стимуляцію дихального центру через блокаду аденозинових рецепторів","Бронходилатацію","Стимуляцію сурфактанту"],a:1,ex:"Аденозин пригнічує дихальний центр. Теофілін блокує аденозинові рецептори → усуває це пригнічення → стимуляція дихання у недоношених. Кофеїн також використовується з цією метою."},
{type:"mcq",q:"Яке показання НЕТИПОВЕ для теофіліну?",o:["Бронхіальна астма","Апное недоношених","Системна артеріальна гіпертензія","Легенева гіпертензія"],a:2,ex:"Теофілін розширює бронхи та легеневі судини, але не застосовується при системній АГ (є більш ефективні та безпечні класи препаратів)."},
{type:"match",q:"Зіставте препарат з механізмом бронходилатації:",pairs:[["Сальбутамол","β2-міметик → цАМФ↑ через аденілатциклазу"],["Теофілін","Інгібітор ФДЕ → цАМФ↑ через уповільнення розщеплення"],["Тіотропій","М3-холіноблокатор → усунення парасимпатичного спазму"],["Монтелукаст","Антагоніст LT-рецепторів → блокада лейкотрієнового бронхоспазму"]],ex:"Різні точки прикладання — всі ведуть до бронходилатації. Цікаво: сальбутамол і теофілін обидва підвищують цАМФ, але різними шляхами → синергізм."}
]},

{id:12,n:"Тіотропію бромід",g:"Дихальна система",grp:"М3-холіноблокатор тривалої дії (ДДАХ)",
mech:"Четвертинна амонієва сполука. Селективний конкурентний антагоніст М3-мускаринових рецепторів. Кінетика дисоціації: повільно від М1 і М3, швидко від М2 → функціонально селективний до М3. Блокада М3 у гладкій мускулатурі бронхів → зниження парасимпатичного бронхоспазму. Блокада М3 у залозах → зниження секреції. Тривалість 24 год. НЕ проникає через ГЕБ.",
ind:"Базова тривала терапія ХОЗЛ (І лінія). Хронічний обструктивний бронхіт. Допоміжна терапія при тяжкій БА.",
side:"Сухість у роті (найчастіший). Запор. Нечіткість зору. Затримка сечовипускання. Загострення глаукоми закритого кута.",
contra:"Глаукома закритого кута (відносне). Аденома простати з обструкцією. Гіперчутливість до тіотропію або атропіну.",
combo:"+ Сальбутамол (КДБА) при ХОЗЛ для купірування. + Індакатерол (ДДБА) — фіксована комбінація при тяжкій ХОЗЛ. Іпратропій — аналог КОРОТКОЇ дії (КДАХ).",
chain:["Блокада М3-рецепторів бронхів","Пригнічення парасимпатичного впливу на бронхи","Тонус гладкої мускулатури ↓","Бронходилатація","Одночасно: блокада М3 залоз → зменшення гіперсекреції слизу","Покращення прохідності ДШ → ↑ ОФВ1"],
tip:"Тіотропій = ТРИВАЛА дія (ДДАХ, раз на добу). Іпратропій = КОРОТКА дія (КДАХ, 4 рази на добу). Четвертинний амоній = НЕ проникає в ЦНС. Стандарт базової терапії ХОЗЛ.",
q:[
{type:"mcq",q:"Тіотропій відрізняється від іпратропію:",o:["Різним рецептором дії","Тривалістю дії: тіотропій — 24 год (ДДАХ), іпратропій — 4-6 год (КДАХ)","Тіотропій є β-міметиком","Іпратропій сильніший за тіотропій"],a:1,ex:"Тіотропій — ДДАХ (довготривалий дихальний антихолінергік, 24 год, раз на добу). Іпратропій — КДАХ (4-6 год, 4 рази на добу). Обидва — М3-холіноблокатори, але різна тривалість."},
{type:"mcq",q:"Чому тіотропій НЕ викликає центральних ефектів?",o:["Малі дози","Рецептор-специфічний (лише М3)","Четвертинна амонієва структура → не проникає через ГЕБ","Швидко руйнується"],a:2,ex:"Четвертинна амонієва структура → постійно заряджена молекула → не проходить через ліпофільний ГЕБ → немає центральних холінолітичних ефектів (збудження, галюцинації)."},
{type:"mcq",q:"Стандарт базової бронходилататорної терапії ХОЗЛ:",o:["Сальбутамол (КДБА)","Тіотропій (ДДАХ) та/або ДДБА (індакатерол)","Теофілін","Флутиказон (ГКС)"],a:1,ex:"Тіотропій (ДДАХ) та ДДБА (індакатерол, формотерол) — стандарт базової бронходилататорної терапії ХОЗЛ (GOLD рекомендації). ГКС — лише при частих загостреннях або БА-ХОЗЛ перекриття."},
{type:"mcq",q:"Який побічний ефект тіотропію потребує моніторингу пацієнтів з аденомою простати?",o:["Поліурія","Затримка сечовипускання","Інконтиненція","Гематурія"],a:1,ex:"М3-рецептори є і в сечовому міхурі та простаті. Блокада → зниження скоротливості детрузора → затримка сечовипускання. При аденомі простати — підвищений ризик гострої затримки сечі."},
{type:"mcq",q:"Тіотропій ПРОТИПОКАЗАНИЙ при:",o:["ХОЗЛ","Глаукомі закритого кута (може спровокувати гострий напад)","Хронічному бронхіті","Тяжкій БА"],a:1,ex:"Глаукома закритого кута: блокада М3-рецепторів в оці → розширення зіниці → підвищення внутрішньоочного тиску → гострий напад глаукоми. Протипоказаний. При глаукомі відкритого кута — можна з обережністю."},
{type:"mcq",q:"Функціональна селективність тіотропію до М3-рецепторів пояснюється:",o:["Хімічною специфічністю до М3","Повільною кінетикою дисоціації від М1 і М3, швидкою від М2","Тільки М3-рецептори є в бронхах","Різна доза для різних підтипів"],a:1,ex:"Кінетична селективність: дисоціює від М2-рецепторів швидко (→ М2 відновлюється → немає постійної тахікардії), але повільно від М1 і М3 (→ тривала бронходилатація та знижена секреція)."}
]},

{id:13,n:"Флутиказон",g:"Дихальна система",grp:"ГКС інгаляційний",
mech:"Синтетичний трифторований глюкокортикостероїд. Звʼязується з внутрішньоклітинними ГКС-рецепторами → комплекс переходить у ядро → пригнічення транскрипції прозапальних генів (цитокіни, ЦОГ-2, іНОС) → зниження синтезу простагландинів, лейкотрієнів, гістаміну, цитокінів. Зменшує набряк слизової, гіперреактивність бронхів, еозинофілію.",
ind:"Базова протизапальна терапія бронхіальної астми (інгаляційно). Алергічний риніт (інтраназально). Дерматози (накожно). Загострення ХОЗЛ.",
side:"Кандидоз ротоглотки (при інгаляції, якщо не полоскати рот). Хриплий голос (дисфонія). Рідко: парадоксальний бронхоспазм. При системному введенні: синдром Кушинга, остеопороз, гіперглікемія.",
contra:"Гострий напад БА (немає швидкого бронходилататорного ефекту). Гіперчутливість.",
combo:"СЕРЕТИД = флутиказон + сальметерол (ГКС + ЛДБА — стандарт базової терапії БА). + Сальбутамол за потребою (КДБА). Беклометазон — інший ГКС того ж класу.",
chain:["Флутиказон інгалюється → осідає на слизовій","Проникнення в клітину","Звʼязування з ГКС-рецептором","Комплекс ГКС-рецептор → переміщення в ядро","Зміна транскрипції: ↓ прозапальні гени","Зниження синтезу простагландинів, ЛТ, цитокінів","Зменшення набряку та гіперреактивності бронхів"],
tip:"Після кожної інгаляції — ПОЛОСКАТИ РОТ (кандидоз!). Ефект розвивається поступово (дні-тижні) → НЕ для гострого нападу. Серетид = флутиказон + сальметерол.",
q:[
{type:"mcq",q:"Яку профілактичну дію необхідно виконувати після інгаляції флутиказону?",o:["Приймати антигрибковий засіб","Полоскати рот водою (профілактика кандидозу ротоглотки)","Вимірювати ОФВ1","Приймати бронходилататор"],a:1,ex:"Залишки ГКС в роті та горлі пригнічують місцевий імунітет → Candida albicans активується → кандидоз ротоглотки. Профілактика: полоскання рота водою або відвару ромашки після КОЖНОЇ інгаляції."},
{type:"mcq",q:"Флутиказон призначають при БА як:",o:["Засіб для купірування гострого нападу","Базову (щоденну) протизапальну терапію","Антибіотик при інфекції","Муколітик"],a:1,ex:"Базова (контролююча, профілактична) терапія. Ефект через дні-тижні. Лікує запалення — основу БА. Не бронходилататор — не для гострих нападів."},
{type:"mcq",q:"Серетид — це:",o:["Поєднання двох β2-міметиків","Флутиказон (ГКС) + сальметерол (ЛДБА)","Тіотропій + сальбутамол","Монтелукаст + беклометазон"],a:1,ex:"Серетид = флутиказон + сальметерол. ГКС (протизапальний) + ЛДБА (бронходилататор тривалої дії) — золотий стандарт базової терапії БА і тяжкої ХОЗЛ."},
{type:"mcq",q:"Побічний ефект інгаляційних ГКС, що виникає при неправильному прийомі (без полоскання):",o:["Системний остеопороз","Кандидоз ротоглотки","Глаукома","Гіперглікемія"],a:1,ex:"Місцевий ефект — залишки ГКС у роті пригнічують місцевий імунітет. Системні ефекти (остеопороз, ЦД, Кушинг) виникають при СИСТЕМНОМУ застосуванні, при інгаляційному — мінімальні."},
{type:"mcq",q:"Ефект флутиказону при БА розвивається:",o:["Протягом 2-3 хвилин","Протягом 15-30 хвилин","Через кілька днів-тижнів регулярного прийому","Через 1 годину"],a:2,ex:"ГКС діють через зміну транскрипції генів → повільно (дні-тижні) при базовому прийомі. Тому їх не можна використовувати як засіб першої допомоги при нападі."},
{type:"case",scenario:"Пацієнт з БА отримує флутиказон 500 мкг/добу. Скаржиться на білий наліт в роті та біль при ковтанні. Тест на Candida позитивний.",q:"Що спричинило кандидоз і як запобігати повторенню?",o:["Алергія на флутиказон — замінити на беклометазон","Кандидоз від ГКС — навчити полоскати рот після кожної інгаляції","Імунодефіцит — призначити антиретровірусну терапію","Надмірна гігієна рота — рекомендувати рідше чистити зуби"],a:1,ex:"Класичне ускладнення інгаляційних ГКС. Лікування: флуконазол або ністатин. Профілактика: полоскання рота водою після кожної інгаляції. Можна також використовувати спейсер — зменшує осадження в ротоглотці."},
{type:"mcq",q:"Флутиказон пригнічує синтез яких медіаторів?",o:["Тільки гістаміну","Простагландинів, лейкотрієнів, цитокінів (ІЛ-4, ІЛ-5, ФНП)","Тільки лейкотрієнів","Серотоніну та дофаміну"],a:1,ex:"ГКС пригнічують синтез ВСІХ прозапальних медіаторів: ПГ (через ↓ ліпокортин → ↓ фосфоліпаза А2), ЛТ, гістамін (з тучних клітин), цитокіни (ІЛ-1, ІЛ-4, ІЛ-5, ФНП-α)."}
]},

{id:14,n:"Сальметерол",g:"Дихальна система",grp:"β2-адреноміметик тривалої дії (ЛДБА)",
mech:"Селективний β2-адреноміметик тривалої дії (12 год). Ліпофільний «хвіст» молекули «заякорює» препарат у ліпідній мембрані клітини поруч з β2-рецептором → повільна дисоціація → тривала активація. Додатково: інгібує дегрануляцію тучних клітин, вивільнення гістаміну, ПГ D2, лейкотрієнів. Пригнічує ранню та пізню алергічну реакцію.",
ind:"Базова тривала бронходилататорна терапія БА (ОБОВ'ЯЗКОВО з ГКС!). ХОЗЛ. Профілактика нічних нападів.",
side:"Гіпокаліємія. Тахікардія. Тремор. Головний біль.",
contra:"Гострий напад БА (повільний початок 15-30 хв → НЕ для ургентного лікування). Монотерапія при БА БЕЗ ГКС (підвищує смертність при БА!).",
combo:"ОБОВ'ЯЗКОВО з ГКС при БА. СЕРЕТИД = сальметерол + флутиказон. НЕ замінює КДБА при нападі.",
chain:["«Хвіст» молекули закріплюється у ліпідній мембрані","Активна голівка активує β2-рецептор","Тривала стимуляція аденілатциклази","цАМФ↑ на 12 годин","Тривала бронходилатація","Паралельно: інгібування дегрануляції тучних клітин"],
tip:"ЛДБА — тільки в комбінації з ГКС при БА! Монотерапія ЛДБА без ГКС → підвищена смертність (FDA Black Box Warning). Не для нападів — повільний початок (15-30 хв).",
q:[
{type:"mcq",q:"Тривалість бронходилататорної дії сальметеролу:",o:["4-6 годин","8 годин","12 годин","24 години"],a:2,ex:"12 годин — ЛДБА (Long-Acting Beta-2 Agonist). Тому приймають двічі на добу (вранці та ввечері). На відміну від сальбутамолу (КДБА, 4-6 год)."},
{type:"mcq",q:"Монотерапія сальметеролом (без ГКС) при БА:",o:["Ефективна та рекомендована","Підвищує ризик важких нападів та смертності (FDA Black Box Warning)","Однакова ефективність, як з ГКС","Доцільна при легкій БА"],a:1,ex:"FDA Black Box Warning (2010): монотерапія ЛДБА при БА підвищує ризик важких нападів та смертності. Механізм: ЛДБА маскує погіршення контролю без лікування запалення. Обов'ЯЗКОВО з ГКС."},
{type:"mcq",q:"Чому сальметерол НЕ підходить для купірування гострого нападу БА?",o:["Не є бронходилататором","Повільний початок дії (15-30 хвилин)","Занадто короткий ефект","Небезпечний при нападі"],a:1,ex:"Початок дії 15-30 хвилин (через механізм «якоря» у мембрані) — занадто повільно для гострого нападу. Для купірування нападу — КДБА (сальбутамол, початок 2-3 хв)."},
{type:"mcq",q:"Яка додаткова антиалергічна дія сальметеролу, якої немає у сальбутамолу?",o:["Блокада гістамінових рецепторів","Інгібування дегрануляції тучних клітин і вивільнення гістаміну, ПГD2, ЛТ","Пригнічення ЦОГ","Блокада IgE"],a:1,ex:"Тривале звʼязування сальметеролу з рецептором дозволяє блокувати дегрануляцію тучних клітин → менше гістаміну, ЛТ, ПГD2 → протиалергічна складова, якої немає у короткодіючого сальбутамолу."},
{type:"mcq",q:"Серетид містить:",o:["Беклометазон + формотерол","Флутиказон + сальметерол","Будесонід + формотерол","Тіотропій + індакатерол"],a:1,ex:"Серетид (Advair у США) = флутиказон (ГКС) + сальметерол (ЛДБА). Символ'єрт — те саме. Фостер = беклометазон + формотерол. Симбікорт = будесонід + формотерол."}
]},

// ════════ КАРДІОЛОГІЯ ════════
{id:15,n:"Аміодарон",g:"Кардіологія",grp:"Антиаритмічний III клас (блокатор K-каналів)",
mech:"Клас III антиаритмічних за Vaughan Williams. Блокує IKr та IKs (K-канали) → подовження 3-ї фази потенціалу дії (реполяризації) → збільшення тривалості ПД та ефективного рефрактерного периоду → зниження збудливості. Додатково: незначна блокада Na-каналів (клас I), β-блокада (клас II), блокада Ca-каналів (клас IV). Містить 37% йоду (тиреоїдна токсичність!).",
ind:"Суправентрикулярна тахікардія. Тріпотіння та фібриляція передсердь (контроль ритму). Шлуночкова тахікардія та фібриляція. ІХС зі зниженою ФВ. WPW-синдром.",
side:"Мікровідкладення в рогівці (у всіх при тривалому прийомі, оборотні). Синьо-сірий колір шкіри (фотосенсибілізація). Тиреоїдна дисфункція (гіпо- або гіпертиреоз). Легеневий фіброз (пневмоніт). Гепатотоксичність. Периферична нейропатія.",
contra:"Синусова брадикардія. Синоатріальна блокада. AV-блокада II-III ступеня. СНSS (синдром слабкості синусового вузла). Вагітність. Гіпертиреоз.",
combo:"Підвищує рівень варфарину (інгібіція CYP2C9 → ↑ INR → кровотеча). Підвищує рівень дигоксину. НЕБЕЗПЕЧНО з препаратами, що подовжують QT.",
chain:["Блокада K-каналів (IKr, IKs)","Сповільнення реполяризації","Подовження фази 3 ПД","Збільшення рефрактерного периоду","Зниження автоматизму та збудливості","Запобігання або купірування аритмії"],
tip:"СИНІЙ КОЛІР ШКІРИ + МІКРОВІДКЛАДЕННЯ В РОГІВЦІ = аміодарон. Найефективніший антиаритмік — але найтоксичніший. Щорічно: функція ЩЖ, легень, печінки, ЕКГ, огляд офтальмолога.",
q:[
{type:"mcq",q:"Аміодарон відноситься до антиаритмічних:",o:["I класу (блокатори Na)","II класу (β-блокатори)","III класу (блокатори K)","IV класу (антагоністи Ca)"],a:2,ex:"III клас за Vaughan Williams — блокатори K-каналів. Подовжують ефективний рефрактерний период без суттєвого впливу на скоротливість (навідміну від I класу)."},
{type:"mcq",q:"Специфічний дерматологічний ефект тривалого прийому аміодарону:",o:["Кропивʼянка","Синьо-сірий відтінок шкіри (особливо на відкритих ділянках)","Псоріазоподібний висип","Вузлова еритема"],a:1,ex:"Аміодаронова пігментація шкіри — синьо-сірий або блакитно-сірий відтінок на відкритих сонцю ділянках через відкладення амінного метаболіту в дермі. Фотосенсибілізація — уникати УФ."},
{type:"mcq",q:"Яку дисфункцію щитовидної залози може спричинити аміодарон?",o:["Тільки гіпотиреоз","Тільки гіпертиреоз","Як гіпо-, так і гіпертиреоз (містить 37% йоду)","Не впливає на ЩЖ"],a:2,ex:"37% молекули аміодарону — йод. Хронічне надходження йоду: ефект Вольфа-Чайкова → гіпотиреоз. АБО йод-індукована активація ЩЖ → гіпертиреоз. Контроль ТТГ кожні 3-6 місяців!"},
{type:"mcq",q:"Офтальмологічний ефект аміодарону (у всіх пацієнтів при тривалому прийомі):",o:["Катаракта","Мікровідкладення в рогівці (кератопатія)","Глаукома","Атрофія зорового нерва"],a:1,ex:"Мікровідкладення в рогівці (вертилятна кератопатія) — у >90% пацієнтів при тривалому прийомі. Виглядає як жовтувато-коричневі лінії при огляді щілинною лампою. Зазвичай безсимптомні. Оборотні після відміни."},
{type:"mcq",q:"Аміодарон ПРОТИПОКАЗАНИЙ при:",o:["Фібриляції передсердь","Шлуночковій тахікардії","Синусовій брадикардії та AV-блокаді II-III","ІХС зі зниженою ФВ"],a:2,ex:"Аміодарон знижує ЧСС і уповільнює AV-провідність → при вже існуючій брадикардії або блокаді → ризик асистолії або зупинки серця."},
{type:"case",scenario:"Пацієнт 58 р. на аміодароні 5 років. Почав скаржитися на задишку, суху кашель. При КТ легень виявлено дифузні інфільтрати.",q:"Найімовірніше ускладнення від аміодарону?",o:["Пневмонія (бактеріальна)","Аміодаронова легенева токсичність (пневмоніт/фіброз)","Серцева недостатність","Туберкульоз"],a:1,ex:"Аміодаронова легенева токсичність (0,1-0,5%/рік) — пневмоніт, що може прогресувати до фіброзу. Симптоми: задишка, кашель, лихоманка. КТ: «матове скло», ущільнення. Лікування: відміна аміодарону, ГКС."},
{type:"mcq",q:"Аміодарон підвищує токсичність варфарину через:",o:["Витіснення з білків плазми","Інгібіцію CYP2C9 → ↓ метаболізм варфарину → ↑ рівень → ↑ INR","Зниження синтезу вітаміну К","Конкуренцію за ниркову екскрецію"],a:1,ex:"Аміодарон інгібує CYP2C9 (метаболізує S-варфарин) → підвищення концентрації варфарину → надмірна антикоагуляція → ризик кровотечі. При призначенні аміодарону — знизити дозу варфарину на 25-50%, контроль INR."},
{type:"mcq",q:"Яку унікальну властивість аміодарону відображає термін 'полікласний антиаритмік'?",o:["Лікує всі типи аритмій","Має ефекти всіх 4 класів: I (Na), II (β-блокада), III (K), IV (Ca)","Приймається 4 рази на добу","Має 4 механізми токсичності"],a:1,ex:"Аміодарон унікально поєднує ефекти: I класу (блокада Na-каналів, ↓ збудливість), II (β-блокада, ↓ ЧСС), III (блокада K-каналів, ↑ рефрактерний период), IV (блокада Ca-каналів, ↓ AV-провідність)."},
{type:"match",q:"Зіставте антиаритмічний клас з препаратом та механізмом:",pairs:[["I клас (Na-блокатори)","Лідокаїн, прокаїнамід — знижують фазу 0 ПД"],["II клас (β-блокатори)","Метопролол, бісопролол — знижують ЧСС"],["III клас (K-блокатори)","Аміодарон, соталол — подовжують ПД"],["IV клас (Ca-блокатори)","Верапаміл, дилтіазем — блокада AV-вузла"]],ex:"Класифікація Vaughan Williams — базова для КРОК. Аміодарон унікально поєднує ефекти всіх 4 класів."}
]},

{id:16,n:"Амлодипін",g:"Кардіологія",grp:"Антагоніст кальцію (дигідропіридин)",
mech:"Блокує Ca2+-канали L-типу в гладкій мускулатурі артеріол > міокарді → зниження внутрішньоклітинного Ca2+ → розслаблення гладких мʼязів → вазодилатація периферичних артеріол → зниження ЗПОС → зниження АТ. Тривала дія (T1/2 ~35-50 год). Має антиангінальну та нефропротекторну дію.",
ind:"Артеріальна гіпертензія. Стенокардія напруги. Стенокардія Принцметала (вазоспастична) — ПРЕПАРАТ ВИБОРУ.",
side:"Набряки гомілок (периферична вазодилатація → підвищена капілярна фільтрація). Рефлекторна тахікардія. Припливи жару. Головний біль.",
contra:"Тяжка гіпотензія. Кардіогенний шок. Нестабільна стенокардія (без β-блокатора).",
combo:"+ іАПФ або сартан при АГ (синергізм). + β-блокатор при стенокардії (нівелює рефлекторну тахікардію). НЕБЕЗПЕЧНО: + верапаміл/дилтіазем → виражена брадикардія.",
chain:["Блокада Ca L-каналів у судинах","Ca2+ не надходить у гладкі міоцити артеріол","Актин-міозинова взаємодія не відбувається","Розслаблення гладкої мускулатури артеріол","Зниження ЗПОС → зниження АТ","Розширення коронарних артерій → антиангінальний ефект"],
tip:"Вазоспастична стенокардія Принцметала — ВИБІР (усуває коронароспазм). Набряки гомілок — специфічний ефект дигідропіридинів. Сухий кашель — НЕ від амлодипіну (від іАПФ).",
q:[
{type:"mcq",q:"Амлодипін є препаратом вибору при:",o:["Стенокардії в поєднанні з серцевою недостатністю (знижена ФВ)","Вазоспастичній (Принцметала) стенокардії","Синусовій тахікардії","Стенозі аортального клапана"],a:1,ex:"Стенокардія Принцметала — коронароспазм. Антагоністи Ca (амлодипін) → розслаблення коронарних артерій → усунення спазму. β-блокатори при Принцметала — протипоказані (можуть посилити спазм через α-переважання)."},
{type:"mcq",q:"Специфічний побічний ефект дигідропіридинових антагоністів Ca:",o:["Сухий кашель","Набряки гомілок","Металевий присмак","Гіперкаліємія"],a:1,ex:"Набряки гомілок — вазодилатація → підвищений гідростатичний тиск в капілярах → вихід рідини в тканини. НЕ серцеві набряки (серцева функція нормальна). Не плутати з сухим кашлем (іАПФ)."},
{type:"mcq",q:"Чим дигідропіридини (амлодипін) відрізняються від верапамілу та дилтіазему?",o:["Однаковий ефект, різна тривалість","Дигідропіридини — переважна вазодилатація; верапаміл/дилтіазем — переважна дія на серце (ЧСС, AV-провідність)","Верапаміл сильніший вазодилататор","Амлодипін пригнічує серце більше"],a:1,ex:"Вазоселективність: дигідропіридини (ніфедипін, амлодипін, нікардипін) — переважно судини, мінімальна кардіодепресія. Верапаміл, дилтіазем — кардіоселективні (↓ ЧСС, ↓ AV-провідність)."},
{type:"mcq",q:"Нефропротективний ефект амлодипіну при ХХН зумовлений:",o:["Діуретичним ефектом","Зниженням системного АТ та внутрішньоклубочкового тиску","Прямою захисною дією на нефрони","Антибактеріальним ефектом"],a:1,ex:"Амлодипін знижує системний АТ → зниження тиску в клубочках → менше гіперфільтрації → нефропротекція. Доповнення до іАПФ/сартанів при ХХН з протеїнурією."},
{type:"mcq",q:"Рефлекторна тахікардія від амлодипіну виникає через:",o:["Пряму стимуляцію синусового вузла","Барорецепторний рефлекс: вазодилатація → ↓ АТ → активація симпатики → ↑ ЧСС","Блокаду парасимпатики","Підвищення катехоламінів"],a:1,ex:"Вазодилатація → зниження АТ → барорецептори дуги аорти → активація СНС → ЧСС↑ (рефлекторна тахікардія). Компенсаторна реакція. Зменшується при комбінації з β-блокатором."}
]},

{id:17,n:"Небіволол",g:"Кардіологія",grp:"Селективний β1-адреноблокатор + вазодилататор (NO)",
mech:"Найселективніший β1-блокатор. Блокує β1-рецептори серця → ↓ ЧСС, ↓ скоротливість, ↓ АТ. Унікально: стимулює синтез NO в ендотелії судин (через β3-рецептори або L-аргінін шлях) → вазодилатація → додаткове зниження АТ та постнавантаження. Метаболічно нейтральний (не порушує ліпідний або глюкозний обмін).",
ind:"АГ. ХСН зі зниженою ФВ (покращує прогноз). Стенокардія.",
side:"Брадикардія. Бронхоспазм (рідко, більш β1-селективний). Холодні кінцівки. Втомлюваність.",
contra:"Тяжка брадикардія. AV-блокада II-III. Кардіогенний шок. Тяжка бронхіальна астма.",
combo:"Обережно + дигоксин (брадикардія). НЕБЕЗПЕЧНО + верапаміл/дилтіазем (виражена брадикардія).",
chain:["Блокада β1-рецепторів серця","↓ ЧСС (негативний хронотропізм)","↓ скоротливість (негативний інотропізм)","↓ потреба міокарда в O2","Стимуляція синтезу NO в ендотелії","Вазодилатація → ↓ постнавантаження"],
tip:"УНІКАЛЬНИЙ серед β-блокаторів: стимулює NO-синтез в ендотелії. Найселективніший β1-блокатор (мінімальний ризик бронхоспазму). Метаболічно нейтральний — при ЦД та дисліпідемії.",
q:[
{type:"mcq",q:"Небіволол унікально відрізняється від інших β-блокаторів тим, що:",o:["Блокує β1 та β2 рецептори","Стимулює синтез NO в ендотелії → додаткова вазодилатація","Є α+β-блокатором","Має антиаритмічну дію III класу"],a:1,ex:"Небіволол стимулює синтез оксиду азоту (NO) в ендотелії судин → вазодилатація → додаткове зниження АТ та постнавантаження. Це є унікальністю, якої немає у більшості β-блокаторів."},
{type:"mcq",q:"Небіволол є найбільш β1-селективним серед β-блокаторів. Що це означає клінічно?",o:["Більш ефективний при ХСН","Мінімальний вплив на β2-рецептори бронхів → нижчий ризик бронхоспазму","Не знижує АТ","Не впливає на ЧСС"],a:1,ex:"Висока β1-селективність → мінімальна блокада β2-рецепторів бронхів → найнижчий ризик бронхоспазму серед β-блокаторів. Відносно безпечніший при ХОЗЛ та БА (але з обережністю)."},
{type:"mcq",q:"Чому небіволол вважається «метаболічно нейтральним»?",o:["Не впливає на артеріальний тиск","Не погіршує ліпідний профіль та глюкозний обмін (на відміну від неселективних β-блокаторів)","Не виводиться нирками","Не метаболізується в печінці"],a:1,ex:"Неселективні β-блокатори (пропранолол) погіршують інсулінорезистентність, підвищують тригліцериди. Небіволол — мінімальний вплив на метаболізм → перевага при ЦД та атерогенній дисліпідемії."}
]},

{id:18,n:"Метопролол",g:"Кардіологія",grp:"Селективний β1-адреноблокатор",
mech:"Конкурентна блокада β1-адренорецепторів серця. Знижує ЧСС (негативний хронотропізм), скоротливість (негативний інотропізм), швидкість AV-провідності (негативний дромотропізм), автоматизм синусового вузла. Знижує вивільнення реніну → знижує рівень ангіотензину II та альдостерону → зниження АТ. Зменшує потребу міокарда в O2 → антиангінальний ефект.",
ind:"АГ. Стабільна стенокардія. ІМ (покращення виживаності). ХСН зі зниженою ФВ (малі дози). Аритмії (суправентрикулярні). Тиреотоксикоз (симптоматично).",
side:"Брадикардія. Гіпотензія. Втомлюваність. Маскування гіпоглікемії у ЦД (крім потовиділення!). Бронхоспазм (менший ризик, ніж пропранолол). Синдром відміни при різкому скасуванні.",
contra:"Тяжка брадикардія. AV-блокада II-III. Кардіогенний шок. Тяжка бронхіальна астма (відносне). Декомпенсована ХСН.",
combo:"+ Дигоксин: синергізм у контролі ЧСС при ФП (але ↑ ризик брадикардії). НЕБЕЗПЕЧНО + верапаміл/дилтіазем. НЕБЕЗПЕЧНО при ЦД + інсулін (маскування гіпоглікемії).",
chain:["Блокада β1-рецепторів синусового вузла","ЧСС ↓ (хронотропізм-)","Блокада β1 у AV-вузлі → уповільнення провідності","Блокада β1 у міокарді → ↓ скоротливість","↓ потреба міокарда в O2","↓ виникнення аритмій"],
tip:"МАСКУЄ гіпоглікемію у діабетиків (крім пітливості — вона холінергічна!). При ХСН — починати з мінімальних доз. Різко НЕ відміняти — синдром відміни (рикошетна тахікардія, нестабільна стенокардія).",
q:[
{type:"mcq",q:"Метопролол є:",o:["Неселективним β-блокатором","Селективним β1-адреноблокатором","β+α блокатором","β2-агоністом"],a:1,ex:"Кардіоселективний β1-блокатор. Переважна блокада β1 (серце, юкстагломерулярний апарат), менший вплив на β2 (бронхи) → менший ризик бронхоспазму, ніж пропранолол."},
{type:"mcq",q:"Метопролол маскує симптоми гіпоглікемії. Яке саме? Що він НЕ маскує?",o:["Маскує пітливість, НЕ маскує тахікардію","Маскує тахікардію та тремор, НЕ маскує пітливість (холінергічний рефлекс)","Маскує всі симптоми","Нічого не маскує"],a:1,ex:"β-блокатори маскують адренергічні симптоми гіпоглікемії: тахікардію, тремор, тривогу. Але НЕ маскують пітливість — вона опосередкована холінергічними рецепторами (не адренергічними). Хворим на ЦД + β-блокатор — орієнтуватися на пітливість!"},
{type:"mcq",q:"При ХСН метопролол починають з:",o:["Максимальної дози (200 мг/добу)","Мінімальної дози (12,5-25 мг/добу) з поступовим нарощуванням протягом тижнів-місяців","В/в введення","Тільки при загостренні"],a:1,ex:"При ХСН β-блокатори спочатку пригнічують і без того знижену функцію серця. Тому починають з мінімальних доз: метопролол сукцинат 12,5 або 25 мг/добу, подвоюючи кожні 2 тижні до цільової."},
{type:"mcq",q:"Синдром відміни метопрололу виникає через:",o:["Зниження рівня метопрололу нижче мінімального","Upregulation β-рецепторів при тривалій блокаді → різка відміна → надмірна адренергічна стимуляція","Алергію до метаболітів","Зниження альдостерону"],a:1,ex:"Тривала блокада β-рецепторів → компенсаторне збільшення їх кількості (upregulation). Різка відміна → рецептори надмірно чутливі → рикошетна тахікардія, гіпертензія, нестабільна стенокардія. Відміняти поступово протягом 2-4 тижнів."},
{type:"mcq",q:"НЕБЕЗПЕЧНА комбінація метопрололу:",o:["Метопролол + амлодипін","Метопролол + верапаміл або дилтіазем","Метопролол + еналаприл","Метопролол + аспірин"],a:1,ex:"Метопролол (β-блокатор) + верапаміл/дилтіазем (Ca-антагоністи, що гальмують серце) = подвійне пригнічення синусового вузла та AV-провідності → виражена брадикардія, AV-блокада, асистолія."}
]},

{id:19,n:"Аспарагінат калію та магнію (Панангін/Аспаркам)",g:"Кардіологія",grp:"Препарат K і Mg (антиаритмічний, кардіопротективний)",
mech:"Забезпечує надходження K+ та Mg2+ у клітини завдяки аспарагіновій кислоті-носію. K+ відновлює нормальний трансмембранний потенціал кардіоміоцитів. Mg2+ — кофактор Na/K-АТФази, антагоніст Ca2+ на рівні клітини, стабілізує ритм. Разом: підтримують нормальну збудливість і провідність міокарда, запобігають гіпокаліємії та гіпомагніємії.",
ind:"Профілактика та лікування гіпокаліємії та гіпомагніємії (при діуретиках). Серцеві аритмії на фоні електролітного дисбалансу. ІХС. Хронічна серцева недостатність. Профілактика дигіталісної інтоксикації.",
side:"Нудота, блювота, діарея. Гіперкаліємія (при нирковій недостатності). Гіпермагніємія (при нирковій недостатності).",
contra:"Тяжка ниркова недостатність. Гіперкаліємія. AV-блокада. Хвороба Аддісона.",
combo:"+ Фуросемід (профілактика гіпокаліємії). + Дигоксин (захист від токсичності при нормальному рівні K).",
chain:["Аспарагінат переносить K+ та Mg2+ через мембрану в клітину","K+ відновлює трансмембранний потенціал спокою","Mg2+ активує Na/K-АТФазу → підтримка градієнтів","Стабілізація електричної активності міокарда","↓ ризик аритмій при гіпокаліємії"],
tip:"Класична комбінація: фуросемід → гіпокаліємія → дигіталісна токсичність. Аспарагінат K/Mg захищає. Також при ІМ та після нього — підтримка електролітів.",
q:[
{type:"mcq",q:"Аспарагінат K і Mg показаний при гіпокаліємії від діуретиків. Який діуретик найчастіше призводить до гіпокаліємії?",o:["Спіронолактон (K-зберігаючий)","Фуросемід (петльовий)","Ацетазоламід","Манітол"],a:1,ex:"Фуросемід блокує Na-K-2Cl котранспортер → K, Na, Cl, Mg виводяться → гіпокаліємія та гіпомагніємія. Аспарагінат K/Mg відновлює обидва електроліти."},
{type:"mcq",q:"Чому гіпокаліємія небезпечна при прийомі дигоксину?",o:["K підсилює виведення дигоксину","K+ конкурує з дигоксином за Na/K-АТФазу: при гіпокаліємії більше дигоксину зв'язується → токсичність","K порушує всмоктування дигоксину","K знижує рівень дигоксину в крові"],a:1,ex:"K+ та дигоксин конкурують за звʼязування з Na+/K+-АТФазою. При гіпокаліємії (менше K+) → більше місць звʼязування для дигоксину → дигіталісна токсичність при нормальній дозі. Корекція K → захист від токсичності."},
{type:"mcq",q:"Роль магнію у серцевій фізіології:",o:["Безпосередньо пригнічує ЧСС","Кофактор Na/K-АТФази, антагоніст Ca2+, стабілізує мембранний потенціал","Стимулює синтез адреналіну","Підвищує чутливість до ангіотензину II"],a:1,ex:"Mg2+ є кофактором понад 300 ферментів. У серці: активує Na/K-АТФазу → підтримка K-Na градієнту, антагонізує Ca → стабілізує збудливість клітин, запобігає тригерній активності."}
]},

{id:20,n:"Еналаприл",g:"Кардіологія",grp:"Інгібітор АПФ (іАПФ)",
mech:"Пролікі (еналаприл) → гідроліз в печінці → еналаприлат (активний). Еналаприлат конкурентно інгібує ангіотензинперетворюючий фермент (АПФ, кінін-2) → ↓ перетворення Анг-I → Анг-II → ↓ вазоконстрикція, ↓ альдостерон, ↓ затримка Na і H2O. Паралельно: АПФ розщеплює брадикінін → при блокаді АПФ брадикінін накопичується → вазодилатація (добре) + кашель (погано). Регресія гіпертрофії ЛШ.",
ind:"АГ. ХСН зі зниженою ФВ. ХХН з протеїнурією (нефропротекція). ІМ. Діабетична нефропатія (нефропротекція). Синдром Рейно.",
side:"СУХИЙ КАШЕЛЬ (15-20%, через накопичення брадикініну — КЛАС-СПЕЦИФІЧНИЙ!). Ангіоневротичний набряк (рідко, але небезпечно). Гіперкаліємія. Гіпотензія першої дози. Погіршення функції нирок при двобічному стенозі ниркових артерій. Тератогенність (ембріо-фетопатія у II-III триместрі).",
contra:"Вагітність (II-III триместр). Двобічний стеноз ниркових артерій (або стеноз єдиної нирки). Ангіоневротичний набряк в анамнезі. Гіперкаліємія.",
combo:"+ Тіазид або петльовий діуретик (синергізм при АГ). + K-зберігаючий діуретик ОБЕРЕЖНО (гіперкаліємія). НЕ поєднувати з НПЗЗ (знижують ниркову перфузію → відміна ефекту). НЕ поєднувати з сартанами (подвійна блокада РААС).",
chain:["Еналаприл (проліки) → гідроліз → еналаприлат","Еналаприлат блокує АПФ","↓ Анг I → Анг II","Менше вазоконстрикції (Анг II↓)","Менше альдостерону → Na та H2O виводяться","Брадикінін накопичується → вазодилатація + кашель","АТ знижується, регресія гіпертрофії ЛШ"],
tip:"КАШЕЛЬ = брадикінін = УСІХ іАПФ. При кашлі → замінити на САРТАН (лозартан). Ангіоневротичний набряк — негайна відміна та адреналін! Не при вагітності.",
q:[
{type:"mcq",q:"Сухий кашель при іАПФ (еналаприл) виникає через:",o:["Алергію на еналаприл","Накопичення брадикініну (АПФ не розщеплює брадикінін)","Бронхоспазм","Пряме подразнення бронхів"],a:1,ex:"АПФ в нормі розщеплює брадикінін. При блокаді АПФ → брадикінін накопичується → подразнення кашльових рецепторів ВДШ → сухий кашель. Клас-специфічний для ВСІХ іАПФ (закінчуються на -прил)."},
{type:"mcq",q:"При непереносимості еналаприлу (кашель) призначають:",o:["Другий іАПФ (рамiприл)","Антагоніст рецепторів АТ-II — сартан (лозартан, валсартан)","Β-блокатор","Антигістамінний засіб від кашлю"],a:1,ex:"Кашель від іАПФ — класовий ефект (від всіх іАПФ). Тому призначати інший іАПФ — безглуздо. Альтернатива: сартани (БРА) — блокують AT1-рецептор, не впливають на АПФ → немає накопичення брадикініну → немає кашлю."},
{type:"mcq",q:"Ангіоневротичний набряк від іАПФ — це:",o:["Косметична проблема","Потенційно смертельне ускладнення, що потребує негайної відміни та адреналіну","Алергічна реакція, що минає без лікування","Рідкісний, але незначний побічний ефект"],a:1,ex:"Ангіоневротичний набряк (гортань, язик, обличчя) — набряк може заблокувати ДШ → асфіксія. Механізм: накопичення брадикініну → підвищення проникності судин. Лікування: негайна відміна іАПФ, в/в адреналін, антигістамінні."},
{type:"mcq",q:"Еналаприл забезпечує нефропротекцію при ЦД через:",o:["Діуретичний ефект","Зниження внутрішньоклубочкового тиску (розширення виносної артеріоли)","Антибактеріальний ефект","Прямий захист подоцитів"],a:1,ex:"Анг II звужує переважно виносну (еферентну) артеріолу → підвищений внутрішньоклубочковий тиск → гіперфільтрація → пошкодження клубочків. іАПФ: ↓ Анг II → розширення виносної → ↓ тиск → нефропротекція."},
{type:"mcq",q:"Небезпека іАПФ при двобічному стенозі ниркових артерій:",o:["Підвищення АТ","Гостра ниркова недостатність","Гіпокаліємія","Протеїнурія"],a:1,ex:"При двобічному стенозі ниркових артерій нирки виживають за рахунок Анг II-опосередкованої констрикції виносної артеріоли → підтримка клубочкового тиску. іАПФ → знімає цей механізм → тиск у клубочку падає → ОНН."},
{type:"case",scenario:"Пацієнтка 34 р. вагітна (28 тижнів), АГ. Приймає еналаприл.",q:"Яка тактика?",o:["Продовжити еналаприл — безпечний при вагітності","Негайно замінити еналаприл на допустимий при вагітності препарат (метилдопа, ніфедипін, лабеталол)","Збільшити дозу еналаприлу","Відмінити всю антигіпертензивну терапію"],a:1,ex:"іАПФ та сартани АБСОЛЮТНО ПРОТИПОКАЗАНІ у II-III триместрі (ембріофетопатія: порушення розвитку нирок плода, олігогідрамніон, контрактури). Замінити на: метилдопа, ніфедипін або лабеталол (безпечні при вагітності)."}
]},

{id:21,n:"Лозартан",g:"Кардіологія",grp:"Антагоніст рецепторів AT-II (БРА, сартан)",
mech:"Лозартан (проліки) → метаболіт E-3174 (активний, 10-40× сильніший). Конкурентний антагоніст AT1-рецептора ангіотензину II. Анг II не може здійснити вазоконстрикцію, стимуляцію альдостерону, гіпертрофію. НЕ інгібує АПФ → брадикінін НЕ накопичується → кашель рідко. Знижує AT за рахунок: ↓ вазоконстрикції, ↓ альдостерону, ↓ реабсорбції Na.",
ind:"АГ (особливо при непереносимості іАПФ через кашель). ХСН. ХХН з протеїнурією. Діабетична нефропатія. Гіпертрофія ЛШ.",
side:"Гіперкаліємія. Гіпотензія першої дози. Запаморочення. Ангіоневротичний набряк (рідше ніж іАПФ, ~10%). Тератогенність.",
contra:"Вагітність. Двобічний стеноз ниркових артерій. Гіперкаліємія.",
combo:"+ Гідрохлортіазид (синергізм при АГ — Козаар Плюс). + Амлодипін. НЕ поєднувати з іАПФ (подвійна блокада РААС).",
chain:["Лозартан → E-3174 (активний метаболіт)","E-3174 блокує AT1-рецептор","Анг II не може звʼязатися з AT1","Немає вазоконстрикції","Немає стимуляції альдостерону","АТ знижується, натрій виводиться","Брадикінін не накопичується → рідко кашель"],
tip:"НЕМАЄ КАШЛЮ — головна перевага над іАПФ. Однаковий органопротективний ефект (нирки, серце). Стандартна заміна еналаприлу при кашлі. При ХСН — вальсартан або кандесартан доведені більше.",
q:[
{type:"mcq",q:"Лозартан відрізняється від еналаприлу тим, що:",o:["Лозартан сильніше знижує АТ","Лозартан рідко викликає кашель (не впливає на брадикінін)","Лозартан не потребує рецепту","Лозартан діє швидше"],a:1,ex:"Лозартан блокує AT1-рецептор, не інгібує АПФ → брадикінін не накопичується → кашель рідко (~1% vs 15-20% у іАПФ). Та сама ефективність щодо АТ та органопротекції."},
{type:"mcq",q:"Лозартан блокує рецептор:",o:["β1-адренорецептор","AT1-рецептор ангіотензину II","α1-адренорецептор","Мінералокортикоїдний рецептор"],a:1,ex:"AT1-підтип рецепторів ангіотензину II — основний ефекторний підтип: вазоконстрикція, альдостерон, гіпертрофія, фіброз. AT2 — захисний (опосередковує вазодилатацію та антипроліферативний ефект)."},
{type:"mcq",q:"Козаар Плюс — це комбінація:",o:["Лозартан + амлодипін","Лозартан + гідрохлортіазид","Лозартан + спіронолактон","Лозартан + метопролол"],a:1,ex:"Козаар Плюс = лозартан + гідрохлортіазид (тіазидний діуретик). Синергізм: РААС-блокада + діуретик = потужний антигіпертензивний ефект із доповнюючими механізмами."}
]}

);

DRUGS.push(
{id:22,n:"Нітрогліцерин",g:"Кардіологія",grp:"Нітрат / донор NO",
mech:"Метаболізується в гладком'язових клітинах з вивільненням NO (оксид азоту). NO активує гуанілатциклазу → цГМФ↑ → ПКG → фосфорилювання та інактивація MLCK → розслаблення гладкої мускулатури судин. Переважна дія на ВЕНИ (венодилатація) → ↓ переднавантаження → ↓ потреба міокарда в O2. При вищих дозах — і артеріодилатація → ↓ постнавантаження.",
ind:"Купірування нападу стенокардії (сублінгвально — перший вибір!). Гострий коронарний синдром. Застійна СН (зниження переднавантаження). Гіпертонічний криз. Набряк легень.",
side:"Головний біль (розширення мозкових судин — найчастіше). Ортостатична гіпотензія. Метгемоглобінемія (великі дози). Нечіткість зору. Толерантність при тривалому прийомі.",
contra:"Тяжка гіпотензія (АТ < 90). Кардіогенний шок. АБСОЛЮТНО: одночасно з інгібіторами ФДЕ-5 (сілденафіл, тадалафіл, варденафіл) → критична гіпотензія, смерть.",
combo:"АБСОЛЮТНО ПРОТИПОКАЗАНО: + сілденафіл (Віагра), тадалафіл, варденафіл → катастрофічна гіпотензія. + β-блокатор (синергізм при стенокардії). + Морфін при ГІМ.",
chain:["Нітрогліцерин → NO у гладких міоцитах","NO активує гуанілатциклазу","цГМФ↑","ПКG фосфорилює MLCK → інактивація","MLCK не може фосфорилювати міозин","Розслаблення гладкої мускулатури судин (вени > артерії)","Переднавантаження ↓ → потреба міокарда в O2 ↓"],
tip:"СУБЛІНГВАЛЬНО при нападі — ефект за 2-3 хв. АБСОЛЮТНО ПРОТИПОКАЗАНИЙ з Віагрою та аналогами! Толерантність: 8-12 годинний «нітратний бездіяльний» інтервал.",
q:[
{type:"mcq",q:"Нітрогліцерин виділяє ефектор:",o:["цАМФ","NO (оксид азоту)","Ацетилхолін","Брадикінін"],a:1,ex:"NO (оксид азоту) — ендотеліальний фактор розслаблення. Нітрогліцерин є донором NO. NO → гуанілатциклаза → цГМФ → вазодилатація."},
{type:"mcq",q:"При нападі стенокардії нітрогліцерин приймають:",o:["Перорально (ковтають)","Сублінгвально (під язик)","Трансдермально","Внутрішньом'язово"],a:1,ex:"Сублінгвально: всмоктування через слизову рота → в кров → ефект через 2-3 хв. Уникає ефекту першого проходження через печінку (де нітрогліцерин майже повністю руйнується при пероральному прийомі)."},
{type:"mcq",q:"Абсолютно протипоказана комбінація нітрогліцерину:",o:["Нітрогліцерин + β-блокатор","Нітрогліцерин + сілденафіл (Віагра)","Нітрогліцерин + аспірин","Нітрогліцерин + морфін"],a:1,ex:"Нітрогліцерин → NO → цГМФ↑. Сілденафіл → інгібіція ФДЕ-5 → цГМФ не розщеплюється → ↑↑. Сукупний ефект: катастрофічне падіння АТ → колапс, смерть. При прийомі сілденафілу за 24-48 год — протипоказано."},
{type:"mcq",q:"Нітрогліцерин переважно зменшує:",o:["Постнавантаження (артеріальний тиск)","Переднавантаження (венозне повернення до серця)","ЧСС","Скоротливість"],a:1,ex:"Нітрати переважно розширюють вени (при терапевтичних дозах) → ↓ венозне повернення → ↓ кінцево-діастолічний об'єм і тиск ЛШ → ↓ переднавантаження → ↓ споживання O2 міокардом."},
{type:"mcq",q:"Толерантність до нітратів виникає через:",o:["Підвищення чутливості рецепторів","Виснаження SH-груп, необхідних для метаболізму NO; окислення гуанілатциклази","Зниження всмоктування","Прискорення метаболізму в печінці"],a:1,ex:"При безперервному надходженні нітратів → виснаження тіольних (SH) груп, необхідних для конверсії нітрату в NO → толерантність. Профілактика: нітрат-вільний інтервал 8-12 год (вночі без пластиру)."},
{type:"case",scenario:"Пацієнт 65 р. з ІХС і стенокардією. Також приймає тадалафіл (Сіаліс). Має напад стенокардії.",q:"Чи можна дати нітрогліцерин?",o:["Так, сублінгвально 1 таблетку","Ні — катастрофічна гіпотензія від поєднання нітрат + інгібітор ФДЕ-5","Так, але половинну дозу","Так, але лише в/в"],a:1,ex:"Тадалафіл має Т1/2 ~17 год. Протипоказано призначати нітрати протягом 48 год після прийому тадалафілу. При нападі — альтернатива: β-блокатор, антагоніст Ca, морфін."},
{type:"mcq",q:"Ізосорбіду мононітрат відрізняється від нітрогліцерину:",o:["Іншим механізмом дії","Тривалістю дії (ізосорбіду мон. — тривала, нітрогліцерин — коротка)","Ізосорбід не містить NO","Ізосорбід діє на міокард, нітрогліцерин на судини"],a:1,ex:"Нітрогліцерин: T1/2 ~2 хв — для купірування нападу. Ізосорбіду мононітрат: T1/2 ~5 год — для тривалої профілактики стенокардії (приймають 1-2 рази на добу з нітрат-вільним інтервалом)."}
]},

{id:23,n:"Фуросемід",g:"Кардіологія/Нефрологія",grp:"Петльовий діуретик (інгібітор Na-K-2Cl)",
mech:"Зворотньо інгібує Na-K-2Cl-котранспортер (NKCC2) у товстій висхідній ділянці петлі Генле → Na+, K+, Cl-, Mg2+, Ca2+ не реабсорбуються → знижується осмолярність мозкового шару нирки → порушується концентраційна функція → масивний ізоосмотичний діурез. Ранній ефект (через 10-15 хв в/в): венодилатація → ↓ переднавантаження (незалежно від діуретичного ефекту).",
ind:"Набряк легень (НЕВІДКЛАДНО в/в). Набряк мозку (разом з манітом). Набряки при СН, цирозі, нефротичному синдромі. АГ (гіпертонічний криз). Гіперкаліємія (форсований діурез). Гіперкальціємія.",
side:"Гіпокаліємія (найнебезпечніша!). Гіпонатріємія. Гіпомагніємія. Метаболічний алкалоз. Гіповолемія → дегідратація. Ototоксичність (при в/в введенні у великих дозах, особливо з аміноглікозидами). Гіперурикемія (подагра).",
contra:"Анурія. Тяжка гіпокаліємія. Алергія на сульфаніламіди (перехресна). Дегідратація.",
combo:"+ Спіронолактон (K-зберігаючий діуретик) — профілактика гіпокаліємії. НЕБЕЗПЕЧНО: + дигоксин (гіпокаліємія → дигіталісна токсичність!). + Аміноглікозиди — підвищення ototоксичності.",
chain:["Блокада NKCC2 у петлі Генле","Na+, K+, Cl- не реабсорбуються","Осмолярність мозкового шару нирки ↓","Концентруюча функція нирки порушується","Масивний ізоосмотичний діурез","↓ обʼєм плазми → ↓ набряки → ↓ АТ"],
tip:"НАЙПОТУЖНІШИЙ діуретик. Гіпокаліємія + дигоксин = СМЕРТЕЛЬНА КОМБІНАЦІЯ. При набряку легень — в/в ТЕРМІНОВО (ефект через 10-15 хв + ранній венодилататорний ефект). Ototоксичність з аміноглікозидами.",
q:[
{type:"mcq",q:"Де в нефроні діє фуросемід?",o:["Проксимальний звивистий каналець","Товста висхідна ділянка петлі Генле","Дистальний звивистий каналець","Збірна трубочка"],a:1,ex:"Na-K-2Cl котранспортер (NKCC2) знаходиться у товстій висхідній ділянці петлі Генле. Саме тут відбувається реабсорбція ~25% відфільтрованого Na. Блокада → потужний натрійурез."},
{type:"mcq",q:"Найнебезпечніший побічний ефект фуросеміду у пацієнта, що приймає дигоксин:",o:["Гіперкаліємія","Гіпокаліємія → посилення дигіталісної токсичності","Гіперкальціємія","Алкалоз"],a:1,ex:"K+ конкурує з дигоксином за Na/K-АТФазу. Гіпокаліємія → більше місць для дигоксину → токсичність (аритмії) при нормальній дозі. Класична небезпечна комбінація."},
{type:"mcq",q:"Ранній ефект в/в фуросеміду при набряку легень (до настання діуретичного ефекту):",o:["Бронходилатація","Венодилатація → ↓ переднавантаження","Позитивний інотропний ефект","Зниження ЧСС"],a:1,ex:"Через 10-15 хв після в/в введення фуросемід викликає венодилатацію → зниження венозного повернення до серця → ↓ переднавантаження → ↓ тиск у легеневих капілярах. Це передує діуретичному ефекту (30-60 хв)."},
{type:"mcq",q:"Фуросемід підвищує екскрецію кальцію. Тому він показаний при:",o:["Гіпокальціємії","Гіперкальціємії (форсований діурез із введенням ФР)","Остеопорозі","Гіпопаратиреозі"],a:1,ex:"Фуросемід посилює виведення Ca із сечею. При гіперкальціємії: фуросемід + в/в введення ФР (фізіологічний розчин) → форсований кальційурез → швидке зниження Са. Тіазиди — навпаки (знижують Ca-екскрецію)."},
{type:"mcq",q:"Чому тіазидні діуретики поєднуються з петльовими при рефрактерних набряках?",o:["Однаковий механізм → подвійна блокада","Тіазиди блокують дистальний каналець → Na не реабсорбується там, де він мав адаптаційно компенсуватись після петльового блокатора — синергізм","Тіазиди усувають гіпокаліємію від петльових","Тіазиди зменшують ototоксичність"],a:1,ex:"Компенсаторна реабсорбція Na у дистальному канальці нівелює частину ефекту петльових. Тіазиди блокують цю компенсацію → синергістичний діуретичний ефект (sequential nephron blockade)."},
{type:"mcq",q:"Ototоксичність фуросеміду найбільш виражена при:",o:["Пероральному прийомі","Внутрішньовенному швидкому введенні великих доз, особливо з аміноглікозидами","Тривалому прийомі малих доз","Комбінації зі спіронолактоном"],a:1,ex:"Фуросемід + аміноглікозиди (гентаміцин, амікацин) = кумулятивна ototоксичність. Механізм: пошкодження волоскових клітин органу Корті. Профілактика: не поєднувати, контролювати рівні АБ."}
]},

{id:24,n:"Спіронолактон",g:"Кардіологія/Нефрологія",grp:"K-зберігаючий діуретик (антагоніст альдостерону)",
mech:"Конкурентний антагоніст мінералокортикоїдних рецепторів альдостерону в клітинах головних клітин дистальних канальців і збірних трубочок → ↓ синтез апікальних Na-каналів (ENaC) та базолатеральної K+-АТФази → Na+ не реабсорбується, K+ не секретується → натрійурез + ретенція K+. Антиандрогенний ефект (блокада андрогенних рецепторів). Антифіброзна дія у серці → ↓ ремоделювання.",
ind:"Первинний гіперальдостеронізм (с-м Конна — ОБА показання: діагностика і лікування). Вторинний гіперальдостеронізм (ХСН, цироз, нефротичний синдром). ХСН зі зниженою ФВ (знижує смертність). Гіпокаліємія від петльових/тіазидних діуретиків. Акне та гірсутизм у жінок.",
side:"ГІПЕРКАЛІЄМІЯ (найнебезпечніший!). Гінекомастія у чоловіків (антиандрогенний). Порушення менструального циклу у жінок. Нудота, діарея.",
contra:"Гіперкаліємія. Хвороба Аддісона. Тяжка ниркова недостатність.",
combo:"+ Фуросемід (класична комбінація — корекція гіпокаліємії). НЕБЕЗПЕЧНО: + іАПФ або сартани (гіперкаліємія). НЕБЕЗПЕЧНО: + препарати калію (K-дієта + спіронолактон + іАПФ = смерть від гіперкаліємії).",
chain:["Спіронолактон конкурує з альдостероном за рецептор","Рецептор зайнятий — синтез ENaC не стимулюється","Na+ залишається в просвіті канальця → виводиться","K+ не секретується → затримується в крові","Слабкий натрійурез + K-збереження"],
tip:"ГІПЕРКАЛІЄМІЯ — головна небезпека (особливо + іАПФ + ХНН). Антифіброзний ефект при ХСН → дослідження RALES. Гінекомастія у чоловіків — через антиандрогенну дію. Еплеренон — аналог без антиандрогенного ефекту.",
q:[
{type:"mcq",q:"Спіронолактон є антагоністом:",o:["Реніну","Мінералокортикоїдних рецепторів альдостерону","Антидіуретичного гормону","Натрійуретичного пептиду"],a:1,ex:"Конкурентний антагоніст альдостеронових (мінералокортикоїдних) рецепторів у дистальних канальцях і збірних трубочках нирок."},
{type:"mcq",q:"Гінекомастія у чоловіків від спіронолактону виникає через:",o:["Підвищення естрогенів","Антиандрогенну дію (блокада рецепторів андрогенів)","Підвищення пролактину","Підвищення ФСГ"],a:1,ex:"Спіронолактон неспецифічно блокує андрогенні рецептори → відносна перевага естрогенів → гінекомастія. Еплеренон (селективніший антагоніст альдостерону) — без антиандрогенного ефекту."},
{type:"mcq",q:"Спіронолактон знижує смертність при ХСН через:",o:["Потужний діуретичний ефект","Антифіброзний ефект в міокарді (блокада альдостерон-індукованого фіброзу)","Гіпотензивний ефект","Антиаритмічний ефект"],a:1,ex:"Дослідження RALES: спіронолактон 25 мг при ХСН II-IV ФК знижував смертність на 30%. Альдостерон стимулює фіброз міокарда і судин. Блокада → ↓ фіброзу → краща функція → ↓ смертність."},
{type:"mcq",q:"Найнебезпечніша комбінація спіронолактону:",o:["Спіронолактон + фуросемід","Спіронолактон + іАПФ + ХНН (гіперкаліємія!)","Спіронолактон + амлодипін","Спіронолактон + бета-блокатор"],a:1,ex:"Спіронолактон (↑ K) + іАПФ (↑ K, ↓ альдостерон) + ХНН (↓ екскреція K) = критична гіперкаліємія → зупинка серця. При такій комбінації — щотижневий контроль K і креатиніну."},
{type:"mcq",q:"Синдром Конна (первинний гіперальдостеронізм) проявляється:",o:["Гіпертензія + гіперкаліємія + алкалоз","Гіпертензія + ГІПОКАЛІЄМІЯ + метаболічний алкалоз","Гіпотензія + гіпонатріємія","Гіпертензія + гіперкальціємія"],a:1,ex:"Первинний гіперальдостеронізм: аденома надниркових залоз → надлишок альдостерону → ↑ реабсорбція Na → гіпертензія; ↑ екскреція K → гіпокаліємія; ↑ екскреція H+ → метаболічний алкалоз. Спіронолактон — препарат вибору."}
]},

{id:25,n:"Дигоксин",g:"Кардіологія",grp:"Серцевий глікозид",
mech:"Оборотньо інгібує Na+/K+-АТФазу кардіоміоцитів → [Na+]i ↑ → Na/Ca-обмінник виводить менше Ca2+ → [Ca2+]i ↑ → посилення актин-міозинової взаємодії → ПОЗИТИВНИЙ ІНОТРОПНИЙ ефект. Підвищення тонусу парасимпатики (вагусний ефект) → НЕГАТИВНИЙ ХРОНОТРОПНИЙ ефект (↓ ЧСС) та НЕГАТИВНИЙ ДРОМОТРОПНИЙ ефект (↓ AV-провідність).",
ind:"ХСН зі зниженою ФВ (покращення симптомів, але не виживаності). Фібриляція та тріпотіння передсердь (контроль ЧСС). Пароксизмальна суправентрикулярна тахікардія.",
side:"ТОКСИЧНІСТЬ (ВУЗЬКИЙ ТЕРАПЕВТИЧНИЙ ІНДЕКС!): Синусова брадикардія. AV-блокада. Шлуночкові аритмії (тригерна активність). Нудота, блювота, анорексія. КСАНТОПСІЯ (жовте бачення). Гінекомастія.",
contra:"Синдром WPW (ризик ФШ!). AV-блокада II-III. Гіпертрофічна кардіоміопатія з обструкцією.",
combo:"НЕБЕЗПЕЧНО: + Фуросемід (гіпокаліємія → ↑ токсичність дигоксину). + Аміодарон (↑ рівень дигоксину на 50%). Антидот: Digibind/DigiFab (антитіла до дигоксину). Гіпокаліємія = найважливіший фактор токсичності.",
chain:["Блокада Na+/K+-АТФази","[Na+]i ↑","Na/Ca-обмінник (NCX) → менше Ca виводиться","[Ca2+]i ↑","Тропонін C звʼязує більше Ca2+","Більш сильне скорочення (позитивний інотроп)","Вагусна стимуляція → ↓ ЧСС, ↓ AV-провідність"],
tip:"Терапевтичний рівень 0,5-2 нг/мл. ГІПОКАЛІЄМІЯ + ДИГОКСИН = НЕБЕЗПЕКА (K конкурує з дигоксином). Ксантопсія = дигіталісна токсичність (Ван Гог!). Антидот: Digibind.",
q:[
{type:"mcq",q:"Дигоксин інгібує:",o:["H+/K+-АТФазу (протонну помпу)","Na+/K+-АТФазу кардіоміоцитів","Ca2+-АТФазу СПР","Аденілатциклазу"],a:1,ex:"Na+/K+-АТФаза — мішень серцевих глікозидів. Не плутати з H+/K+-АТФазою — мішень ІПП (омепразол). Блокада Na/K-АТФази → [Na+]i↑ → NCX → [Ca2+]i↑ → позитивний інотроп."},
{type:"mcq",q:"Чому ксантопсія (жовте бачення) є ознакою дигіталісної інтоксикації?",o:["Дигоксин забарвлює кришталик","Токсичний вплив дигоксину на фоторецептори сітківки","Підвищення жовчного пігменту","Набряк зорового нерва"],a:1,ex:"Ксантопсія (жовте або зеленувате бачення) — ознака передозування серцевих глікозидів, описана ще у Ван Гога. Токсичний вплив на фоторецептори сітківки. Художник, ймовірно, мав дигіталісну токсичність."},
{type:"mcq",q:"Гіпокаліємія підсилює токсичність дигоксину тому що:",o:["K швидше виводить дигоксин з організму","K+ конкурує з дигоксином за звʼязування з Na/K-АТФазою: при ↓ K → більше доступних місць для дигоксину","K підвищує всмоктування дигоксину","K змінює розподіл дигоксину в тканинах"],a:1,ex:"Na/K-АТФаза має сайт для K+ та для дигоксину (конкуренція). При гіпокаліємії → менше K для звʼязування → більше вільних місць → дигоксин зв'язується більше → токсичність при нормальній концентрації."},
{type:"mcq",q:"Дигоксин протипоказаний при синдромі WPW, тому що:",o:["Підвищує ЧСС при ФП","Уповільнює AV-вузол, але може прискорювати додатковий шлях (пучок Кента) → ФП переходить у ФШ","Викликає бронхоспазм","Підвищує рівень K"],a:1,ex:"При WPW: дигоксин блокує AV-вузол → збудження йде через пучок Кента з максимальною частотою → надшлуночкова тахікардія може перейти у фібриляцію шлуночків. НЕБЕЗПЕЧНО!"},
{type:"mcq",q:"Антидот при дигіталісній інтоксикації:",o:["Налоксон","Флумазеніл","Digibind (Fab-фрагменти антитіл до дигоксину)","Атропін"],a:2,ex:"Digibind/DigiFab — Fab-фрагменти овечих антитіл до дигоксину. Звʼязують дигоксин у крові → нирки виводять комплекс. При загрожуючих аритміях, зупинці серця від передозування дигоксину."},
{type:"mcq",q:"Терапевтичний рівень дигоксину в крові:",o:["0,01-0,05 нг/мл","0,5-2,0 нг/мл","5-10 нг/мл","10-20 нг/мл"],a:1,ex:"0,5-2,0 нг/мл — вузький терапевтичний діапазон. Нижче 0,5 нг/мл — неефективний. Вище 2,0 нг/мл — ризик токсичності. Контроль рівня необхідний регулярно, особливо при порушенні функції нирок."}
]}
);

DRUGS.push(
// ════════ АНТИБІОТИКИ ════════
{id:26,n:"Амоксицилін",g:"Антибіотики",grp:"Амінопеніцилін (β-лактам, широкий спектр)",
mech:"β-лактамний антибіотик. Незворотньо звʼязується з пеніцилін-звʼязуючими білками (PBP — транспептидазами) бактерій → інгібування транспептидази → неможливість поперечного зшивання пептидоглікану клітинної стінки → структурно ослаблена стінка → осмотичний лізис бактерії (бактерицидна дія). Чутливий до β-лактамаз (пеніциліназ) Гр- бактерій.",
ind:"Отит, синусит, тонзиліт. Позагоспітальна пневмонія (у поєднанні). Цистит, пієлонефрит. Ерадикація H.pylori (трійна схема). Лайм-бореліоз. Листеріоз.",
side:"Алергічні реакції (кропивʼянка, анафілаксія — 0,01%). Діарея, дисбіоз. Псевдомембранозний коліт (C.difficile). Кандидоз слизових. Висип при мononуклеозі.",
contra:"Алергія на пеніциліни (перехресна з цефалоспоринами ~10%). Інфекційний мononуклеоз (вірусний гепатит, ЦМВ-мononуклеоз) — специфічний висип.",
combo:"АУГМЕНТИН = амоксицилін + клавуланат (захист від β-лактамаз). + Кларитроміцин + ІПП при H.pylori. Синергізм з аміноглікозидами при важких інфекціях.",
chain:["Пенетрація через пори клітинної стінки Гр+ або Гр- бактерій","Звʼязування з PBP (транспептидазою)","Інгібування транспептидази","Порушення поперечного зшивання пептидоглікану","Структурна слабість клітинної стінки","Осмотичний лізис → загибель бактерії"],
tip:"Безпечний при вагітності (категорія B). При H.pylori — трійна схема: амоксицилін + кларитроміцин + ІПП. При алергії до пеніцилінів — ОБЕРЕЖНО з цефалоспоринами (перехресна ~10%).",
q:[
{type:"mcq",q:"Аугментин містить:",o:["Амоксицилін + ципрофлоксацин","Амоксицилін + клавулановa кислота","Ампіцилін + сульбактам","Амоксицилін + метронідазол"],a:1,ex:"Аугментин = амоксицилін + клавуланат. Клавуланова кислота — інгібітор β-лактамаз (необоротній 'суїцидний' субстрат для β-лактамаз). Захищає амоксицилін від руйнування."},
{type:"mcq",q:"Стандартна трійна схема ерадикації H.pylori:",o:["Амоксицилін + метронідазол тільки","Амоксицилін + кларитроміцин + ІПП (7-14 днів)","Ванкоміцин + метронідазол + ФамотидинHope","Тетрациклін + вісмут + ІПП"],a:1,ex:"Трійна схема (перша лінія): ІПП (омепразол 20 мг 2р/д) + амоксицилін 1 г 2р/д + кларитроміцин 500 мг 2р/д × 7-14 днів. Ефективність 70-85%."},
{type:"mcq",q:"Чому при інфекційному мononуклеозі амоксицилін ПРОТИПОКАЗАНИЙ?",o:["Вірус резистентний до амоксициліну","Виникає специфічний дифузний макулопапульозний висип (не алергія!)","Амоксицилін пригнічує імунітет","Амоксицилін підвищує вірусне навантаження"],a:1,ex:"При мononуклеозі (вірус Епштейна-Барра) + амоксицилін (або ампіцилін) → специфічна дифузна макулопапульозна висипка у ~70-90% пацієнтів. Це не алергія, а специфічна вірусно-медикаментозна реакція."},
{type:"mcq",q:"Механізм дії β-лактамних антибіотиків:",o:["Інгібування ДНК-гірази","Блокада 30S рибосоми","Інгібування транспептидази (PBP) → порушення синтезу клітинної стінки","Порушення проникності цитоплазматичної мембрани"],a:2,ex:"PBP (Penicillin-Binding Proteins) = транспептидази. β-лактамне кільце ковалентно звʼязується з активним центром PBP → фермент блокований → пептидоглікан не формується → осмотичний лізис."},
{type:"mcq",q:"Яке покоління пеніцилінів представляє амоксицилін?",o:["Природний пеніцилін (G)","Пеніциліназостійкий (оксацилін)","Широкого спектру (амінопеніцилін)","Антипсевдомонадний (карбеніцилін)"],a:2,ex:"Амоксицилін — напівсинтетичний амінопеніцилін широкого спектру. Активний проти Гр+ (стафілококи, стрептококи без MRSA) і Гр- (E.coli, Haemophilus). Чутливий до β-лактамаз."},
{type:"case",scenario:"Пацієнт 28 р. з підозрою на бактеріальний тонзиліт. При аускультації: збільшені лімфовузли, збільшена печінка та селезінка. Тест на стрептококовий антиген негативний.",q:"Чи можна призначити амоксицилін?",o:["Так, стандартна доза","Ні — клінічна картина підозріла на мononуклеоз; амоксицилін → специфічний висип","Так, але в половинній дозі","Ні, лише Аугментин"],a:1,ex:"Гепатоспленомегалія + лімфаденопатія + негативний стрептококовий тест = мononуклеоз. Амоксицилін → дифузний висип. Лікування мononуклеозу: симптоматичне (анальгетики, відпочинок). При суперінфекції стрептококом — клариtроміцин або цефалоспорин."}
]},

{id:27,n:"Ампіцилін",g:"Антибіотики",grp:"Амінопеніцилін (β-лактам)",
mech:"Аналогічно амоксициліну — інгібує транспептидазу (PBP). Відрізняється: гірше всмоктується перорально (~40% vs 80% амоксициліну), але є формою для в/в введення. Спектр подібний до амоксициліну. Чутливий до β-лактамаз. Ампіцилін+сульбактам (Уназин) = захищений аналог.",
ind:"Бактеріальний менінгіт (Listeria monocytogenes, H.influenzae). Сальмонельоз. Ентерококові інфекції. Лістеріоз при вагітності.",
side:"Ті ж, що й амоксицилін. Висип (частіше, ніж амоксицилін). Діарея.",
contra:"Алергія на пеніциліни. Мononуклеоз.",
combo:"+ Гентаміцин при ентерококових інфекціях (синергізм). Уназин (ампіцилін + сульбактам).",
chain:["Інгібування PBP → порушення синтезу клітинної стінки → загибель бактерії"],
tip:"Ампіцилін призначають в/в при тяжких інфекціях (менінгіт, сепсис). Перорально — погано всмоктується, тому краще амоксицилін. При лістеріозі у вагітних — ампіцилін + гентаміцин.",
q:[
{type:"mcq",q:"При якому збуднику менінгіту препаратом вибору є ампіцилін?",o:["Neisseria meningitidis","Listeria monocytogenes","Streptococcus pneumoniae","Cryptococcus neoformans"],a:1,ex:"Listeria monocytogenes резистентна до цефалоспоринів (не покривається стандартними схемами менінгіту). Ампіцилін — стандарт лікування лістеріозного менінгіту (особливо у вагітних, літніх, іммуноскомпрометованих)."},
{type:"mcq",q:"Ампіцилін відрізняється від амоксициліну:",o:["Більш широким спектром","Гіршим пероральним всмоктуванням (~40% vs 80%) і наявністю форми для парентерального введення","Відсутністю ризику алергії","Активністю проти MRSA"],a:1,ex:"Пероральний ампіцилін погано всмоктується (40%). При однаковому спектрі — для перорального прийому краще амоксицилін (80%). Але ампіцилін є у в/в формі → при тяжких інфекціях."}
]},

{id:28,n:"Амфотерицин В",g:"Антибіотики",grp:"Протигрибковий поліеновий антибіотик",
mech:"Звʼязується з ергостеролом клітинної мембрани грибів (аналог холестеролу у людей) → утворення пор у мембрані → витікання К+, Mg2+, інших клітинних компонентів → загибель клітини гриба (фунгіцидна дія). Має менший афінітет до холестеролу людських клітин (звідси токсичність).",
ind:"Тяжкі системні мікози: кандидемія, криптококовий менінгіт (особливо при ВІЛ), аспергільоз, гістоплазмоз, кокцидіоідомікоз. Вісцеральний лейшманіоз.",
side:"НЕФРОТОКСИЧНІСТЬ (головне обмеження — у всіх пацієнтів!). Гарячка, озноб, головний біль (під час інфузії). Гіпокаліємія, гіпомагніємія. Анемія. Флебіт.",
contra:"Тяжка ниркова недостатність. Обережно при призначенні інших нефротоксичних препаратів.",
combo:"+ Флуцитозин при криптококовому менінгіті (синергізм). НЕБЕЗПЕЧНО: + нефротоксичні (аміноглікозиди, ванкоміцин, ЦСА) → кумулятивна нефротоксичність.",
chain:["Звʼязування з ергостеролом мембрани гриба","Порушення цілісності мембрани (пори)","Витік K+, Mg2+, нуклеотидів","Порушення ОВП та внутрішнього середовища клітини","Загибель гриба"],
tip:"'Амфо-Терорибл' (прізвисько через токсичність). ЗАВЖДИ контролювати функцію нирок, електроліти. Ліпосомальна форма (Амбізом) — значно менш токсична. Резерв для важких системних мікозів.",
q:[
{type:"mcq",q:"Амфотерицин В звʼязується з:",o:["Ланостеролом бактерій","Ергостеролом клітинної мембрани грибів","Холестеролом клітин людини","Пептидогліканом клітинної стінки"],a:1,ex:"Ергостерол — стеринова складова мембрани грибів (аналог холестеролу у ссавців). Амфотерицин В звʼязується з ергостеролом → пори → загибель гриба. Токсичність для людини — через меншу, але наявну взаємодію з холестеролом."},
{type:"mcq",q:"Головний обмеження амфотерицину В у клінічній практиці:",o:["Вузький спектр протигрибкової активності","Нефротоксичність (практично у всіх пацієнтів)","Погана ефективність","Оральна форма відсутня"],a:1,ex:"Нефротоксичність — у всіх пацієнтів при системному застосуванні. Механізм: звуження аферентних артеріол нирок + пряма тубулярна токсичність. Ліпосомальний амфотерицин В значно безпечніший."},
{type:"mcq",q:"При ВІЛ-асоційованому криптококовому менінгіті стандартна схема лікування:",o:["Флуконазол монотерапія","Амфотерицин В + флуцитозин (2 тижні) → потім флуконазол","Ітраконазол + флуцитозин","Лише вориконазол"],a:1,ex:"Індукція: амфотерицин В 0,7 мг/кг/д + флуцитозин 100 мг/кг/д × 2 тижні. Консолідація: флуконазол 400 мг/д × 8 тижнів. Підтримка: флуконазол 200 мг/д (при ВІЛ до відновлення імунітету)."},
{type:"mcq",q:"Ліпосомальний амфотерицин В (Амбізом) порівняно зі звичайним:",o:["Менш ефективний","Значно менш нефротоксичний при збереженій ефективності","Дешевший та доступніший","Менш ефективний проти Candida"],a:1,ex:"Ліпосомальна форма: ліпосоми доставляють препарат переважно в осередок інфекції (макрофаги), зменшуючи взаємодію з нирками. Нефротоксичність значно нижча, але ціна вища."}
]},

{id:29,n:"Ванкоміцин",g:"Антибіотики",grp:"Глікопептидний антибіотик",
mech:"Звʼязується з C-кінцевим D-аланіл-D-аланіном (D-Ala-D-Ala) пептидогліканового попередника → стерична блокада → транспептидаза не може здійснити зшивання → порушення синтезу клітинної стінки → загибель бактерії (бактерицидний). Не руйнується β-лактамазами (різна точка прикладання від β-лактамів).",
ind:"MRSA (метицилін-резистентний S.aureus). Важкі Гр+ інфекції (сепсис, ендокардит, пневмонія). Псевдомембранозний коліт C.difficile (перорально — не всмоктується, діє місцево). Профілактика у алергічних до пеніцилінів при кардіохірургії.",
side:"'Синдром червоної людини' (при швидкому в/в → вивільнення гістаміну → гіперемія обличчя, шиї, грудей). Нефротоксичність. Ototоксичність. Флебіт.",
contra:"Гіперчутливість. Обережно при нирковій недостатності (корекція дози).",
combo:"+ Рифампіцин при MRSA-ендокардиті (синергізм). НЕБЕЗПЕЧНО: + аміноглікозиди (кумулятивна нефро+ototоксичність). + фуросемід → ototоксичність.",
chain:["Дифузія до клітинної стінки (лише Гр+, не проходить зовнішню мембрану Гр-)","Звʼязування з D-Ala-D-Ala ланцюга пептидоглікану","Транспептидаза стерично блокована субстратом","Зшивання пептидоглікану неможливе","Клітинна стінка не формується → загибель"],
tip:"'Синдром червоної людини' — НЕ алергія, а гістамін-залежна реакція. Профілактика: введення повільно (60-90 хв) + антигістамінні. Стандарт лікування MRSA.",
q:[
{type:"mcq",q:"Ванкоміцин є препаратом вибору при:",o:["Звичайній пневмококовій пневмонії","MRSA-інфекціях (метицилін-резистентний S.aureus)","Туберкульозі","Грибкових інфекціях"],a:1,ex:"MRSA резистентний до всіх β-лактамів (через змінений PBP2a, що не звʼязує β-лактами). Ванкоміцин — не β-лактам, діє на D-Ala-D-Ala → стандарт лікування MRSA."},
{type:"mcq",q:"'Синдром червоної людини' від ванкоміцину — це:",o:["Анафілаксія (IgE-опосередкована)","Неалергійне вивільнення гістаміну при швидкому введенні (почервоніння, гіпотензія, свербіж)","Тяжка алергічна реакція","Фотосенсибілізація"],a:1,ex:"Не алергія! Пряме вивільнення гістаміну з тучних клітин при швидкому введенні ванкоміцину. Профілактика: вводити повільно (60-90 хв) + антигістамінні перед введенням. Якщо алергія — то IgE-тест."},
{type:"mcq",q:"При псевдомембранозному коліті (C.difficile) ванкоміцин призначають:",o:["Внутрішньовенно","Перорально (локальна дія в кишківнику)","Внутрішньом'язово","Ректально"],a:1,ex:"Пероральний ванкоміцин НЕ всмоктується з ШКТ → залишається в просвіті кишківника → висока концентрація там, де є C.difficile. В/в форма не досягає кишківника в достатній концентрації."},
{type:"mcq",q:"Механізм дії ванкоміцину відрізняється від β-лактамів тим, що:",o:["Ванкоміцин блокує фермент (PBP), β-лактами — субстрат","β-лактами блокують PBP-фермент, ванкоміцин — субстрат (D-Ala-D-Ala) → різні точки прикладання","Механізм однаковий, різна молекула","Ванкоміцин не впливає на клітинну стінку"],a:1,ex:"β-лактами: ковалентно блокують PBP (транспептидазу). Ванкоміцин: звʼязує субстрат (D-Ala-D-Ala) → стерично блокує доступ транспептидази до субстрату. MRSA резистентний до β-лактамів (змінений PBP), але чутливий до ванкоміцину."},
{type:"mcq",q:"Чому ванкоміцин неефективний проти більшості Гр- бактерій?",o:["Гр- бактерії мають змінений D-Ala-D-Ala","Ванкоміцин не проникає через зовнішню мембрану Гр- бактерій","Гр- бактерії руйнують ванкоміцин","Ванкоміцин інактивується ліпополісахаридом"],a:1,ex:"Зовнішня мембрана Гр- бактерій є непроникною бар'єром для великих гідрофільних молекул (ванкоміцин MW ~1448). Гр+ бактерії — без зовнішньої мембрани → ванкоміцин вільно проходить до клітинної стінки."}
]},

{id:30,n:"Азитроміцин",g:"Антибіотики",grp:"Макролід (азалід, III покоління)",
mech:"Звʼязується з 23S рРНК 50S субодиниці рибосоми бактерій → блокування транслокації пептидил-тРНК → незавершений поліпептид → пригнічення синтезу бактеріального білка. Бактеріостатичний (бактерицидний при концентраціях >> МПК). Накопичується в фагоцитах (лізосомах) та тканинах → Т1/2 ~68 год → постантибіотичний ефект.",
ind:"Позагоспітальна пневмонія (особливо атипова: хламідія, мікоплазма, легіонела). Тонзиліт, синусит, отит. Кашлюк. Хламідіоз (одна доза 1 г). Гонорея (у поєднанні). H.pylori (схеми другої лінії).",
side:"Подовження QT (аритмія Torsades de Pointes!). Нудота, діарея (найчастіші). Зворотна нейросенсорна глухота (при великих дозах). Гепатотоксичність. Алергія.",
contra:"Алергія на макроліди. Тяжка хвороба печінки. Подовження QT в анамнезі. Одночасно з іншими препаратами, що подовжують QT.",
combo:"Обережно + варфарин (підвищує INR). + Дигоксин (підвищує рівень дигоксину). НЕБЕЗПЕЧНО + аміодарон (обидва подовжують QT).",
chain:["Накопичення в фагоцитах (нейтрофіли, макрофаги, моноцити)","Доставка у вогнище інфекції фагоцитами","Вивільнення азитроміцину","Звʼязування з 50S рибосомою бактерії","Блокада транслокації → пригнічення синтезу білка","Загибель або затримка росту бактерій"],
tip:"50S = макроліди, лінкозаміди (кліндаміцин), хлорамфенікол. 30S = аміноглікозиди, тетрацикліни. Подовження QT! Накопичення в тканинах → T1/2 68 год → приймати 1 раз/добу.",
q:[
{type:"mcq",q:"Азитроміцин впливає на:",o:["30S субодиницю рибосоми","50S субодиницю рибосоми","ДНК-гіразу","Синтез клітинної стінки"],a:1,ex:"50S субодиниця (23S рРНК). Запамятай: 50S — макроліди (азитроміцин, кларитроміцин), лінкозаміди (кліндаміцин), хлорамфенікол. 30S — аміноглікозиди (гентаміцин), тетрацикліни."},
{type:"mcq",q:"Серйозний кардіологічний побічний ефект азитроміцину:",o:["Брадикардія","Подовження QT → ризик Torsades de Pointes","AV-блокада","Серцева недостатність"],a:1,ex:"Азитроміцин блокує hERG-канали (IKr) → подовження QT → ризик шлуночкової тахікардії Torsades de Pointes. Ризик вищий при: гіпокаліємії, вихідному подовженні QT, поєднанні з іншими препаратами, що подовжують QT."},
{type:"mcq",q:"Азитроміцин ефективний при атиповій пневмонії (Mycoplasma, Chlamydophila) тому що:",o:["Діє на клітинну стінку","Проникає всередину клітин (внутрішньоклітинна концентрація >> позаклітинна)","Активний проти всіх Гр+ бактерій","Руйнує β-лактамази"],a:1,ex:"Мікоплазма та хламідія — внутрішньоклітинні патогени без клітинної стінки. Азитроміцин накопичується в фагоцитах → доставляється всередину клітин → ефективний проти внутрішньоклітинних збудників."},
{type:"mcq",q:"Чому курс азитроміцину при хламідіозі — лише 1 прийом (1 г)?",o:["Один прийом достатній через великий обʼєм розподілу і тривалий T1/2 (68 год) у тканинах","Більше доз токсично","Хламідія резистентна до кратних доз","Тільки 1 таблетка в упаковці"],a:0,ex:"T1/2 ~68 год + висока концентрація в тканинах (зокрема в сечостатевих) → тривала бактерицидна концентрація після однократної дози. Пр. хламідіоз: азитроміцин 1 г одноразово = 7-денний курс доксицикліну."},
{type:"match",q:"Зіставте антибіотик з мішенню в рибосомі:",pairs:[["Азитроміцин (макролід)","50S субодиниця (23S рРНК)"],["Гентаміцин (аміноглікозид)","30S субодиниця (16S рРНК)"],["Тетрациклін","30S субодиниця (блокада тРНК)"],["Хлорамфенікол","50S субодиниця (пептидилтрансфераза)"]],ex:"50S: макроліди, лінкозаміди, хлорамфенікол. 30S: аміноглікозиди, тетрацикліни. Знання мішені → розуміння перехресної резистентності та взаємодій."},
{type:"mcq",q:"Азитроміцин III покоління (азалід) відрізняється від еритроміцину (I покоління) тим що:",o:["Однакові по всіх параметрах","15-членне лактонне кільце (азалід) vs 14-членне (еритроміцин), ширший спектр, менше ГІ ефектів, довший T1/2","Азитроміцин дорожчий","Еритроміцин активніший"],a:1,ex:"Азитроміцин (азалід) — 15-членне кільце. Еритроміцин — 14-членне. Азитроміцин: ширший спектр (Гр-, атипові), менше ГІ-побічних, T1/2 68 год (vs 4 год у еритроміцину), менше взаємодій з CYP3A4."}
]},

{id:31,n:"Кларитроміцин",g:"Антибіотики",grp:"Макролід II покоління",
mech:"14-членний макролід. Звʼязується з 50S рибосомою → блокада транслокації → пригнічення синтезу білка. Активний метаболіт 14-OH кларитроміцин підвищує ефективність. Пригнічує CYP3A4 (багато взаємодій!). Ефективний проти H.pylori, Mycobacterium avium complex.",
ind:"Позагоспітальна пневмонія. Синусит, отит. Ерадикація H.pylori (I і II лінія). MAC-інфекція при ВІЛ. Шкірні та мʼяких тканин інфекції.",
side:"Гіркий присмак у роті (металевий). Нудота, блювота. Подовження QT. Гепатотоксичність.",
contra:"Алергія. Тяжке захворювання печінки. Одночасно: симвастатин, ловастатин (ризик рабдоміолізу!), варфарин (↑ INR).",
combo:"В схемах H.pylori: + ІПП + амоксицилін. НЕБЕЗПЕЧНО: + симвастатин → рабдоміоліз. + теофілін → ↑ рівень теофіліну.",
chain:["Звʼязування з 50S рибосомою","Блокада транслокації","Метаболіт 14-OH кларитроміцин — додатковий ефект","Пригнічення синтезу бактеріального білка"],
tip:"Гіркий металевий присмак — специфічна ознака кларитроміцину. Інгібітор CYP3A4 → багато взаємодій: статини, теофілін, варфарин, дигоксин. В схемах ерадикації H.pylori.",
q:[
{type:"mcq",q:"Специфічний побічний ефект кларитроміцину:",o:["Ринорея","Металевий/гіркий присмак у роті","Зміна кольору шкіри","Бронхоспазм"],a:1,ex:"Металевий або гіркий присмак — специфічний для кларитроміцину (виникає у 3-5% пацієнтів). Зумовлений метаболітом, що виділяється зі слиною."},
{type:"mcq",q:"Кларитроміцин НЕБЕЗПЕЧНИЙ у поєднанні зі статинами (симвастатин, ловастатин) через:",o:["Підвищення ефекту антибіотика","Інгібіцію CYP3A4 → підвищення рівня статину → міопатія/рабдоміоліз","Зниження ефекту статину","Взаємну нейтралізацію"],a:1,ex:"Кларитроміцин сильний інгібітор CYP3A4 → метаболізм симвастатину та ловастатину (субстрати CYP3A4) знижується → рівень статину підвищується → ризик міопатії та рабдоміолізу."},
{type:"mcq",q:"Кларитроміцин активний проти H.pylori. У якій схемі ерадикації він використовується?",o:["Монотерапія 2 тижні","Трійна схема: ІПП + амоксицилін + кларитроміцин","Чотирна схема: вісмут + тетрациклін + метронідазол + ІПП","В/в монотерапія"],a:1,ex:"Стандартна трійна схема (I лінія): ІПП + амоксицилін + кларитроміцин × 7-14 днів. При резистентності до кларитроміцину — схеми II лінії з метронідазолом або вісмутом."}
]},

{id:32,n:"Амікацин",g:"Антибіотики",grp:"Аміноглікозид (напівсинтетичний)",
mech:"Незворотньо звʼязується з 30S субодиницею (16S рРНК) рибосоми → порушення зчитування мРНК (помилкове рахування кодонів) → синтез функціонально неповноцінних або нонсенс-білків → вбудовування в мембрану → додаткова проникність → більше аміноглікозиду входить → БАКТЕРИЦИДНИЙ ефект. Аеробний механізм транспорту (анаероби — резистентні!).",
ind:"Тяжкі Гр- інфекції (Pseudomonas, Klebsiella, E.coli, Acinetobacter). Сепсис. Пневмонія (госпітальна). Туберкульоз (при резистентності). Найактивніший аміноглікозид (стійкий до ферментів інактивації).",
side:"OTOTОКСИЧНІСТЬ (необоротна — пошкодження зовнішніх волоскових клітин кохлеарного органу). Нефротоксичність (оборотна). Нервово-мʼязовий блок (при великих дозах).",
contra:"Вагітність (категорія D — необоротна глухота у плода). Міастенія. Тяжка ниркова недостатність.",
combo:"+ β-лактами синергізм при важких інфекціях (спільно входять у клітину). НЕБЕЗПЕЧНО: + ванкоміцин, фуросемід → кумулятивна oto- і нефротоксичність.",
chain:["Активний захоплення аміноглікозиду через O2-залежний транспорт","Звʼязування з 30S рибосомою (16S рРНК)","Помилкове зчитування мРНК → аномальні білки","Аномальні білки вбудовуються в мембрану → пори","Більше аміноглікозиду надходить → посилення ефекту","Загибель бактерії"],
tip:"30S = аміноглікозиди + тетрацикліни. Ototоксичність НЕОБОРОТНА — моніторинг слуху! Не при вагітності. Анаероби — резистентні (потрібен O2 для транспорту). Разове добове дозування (once-daily) знижує токсичність.",
q:[
{type:"mcq",q:"Амікацин звʼязується з:",o:["50S рибосомою","30S рибосомою (16S рРНК)","ДНК-гіразою","Клітинною стінкою"],a:1,ex:"30S субодиниця. Аміноглікозиди → помилкове зчитування кодонів → неправильні білки → вбудовуються в мембрану → пори → більше АГ всередині → бактерицидний ефект."},
{type:"mcq",q:"Ototоксичність аміноглікозидів:",o:["Оборотна — слух відновлюється після відміни","Необоротна — пошкодження зовнішніх волоскових клітин Корті","Тимчасова при будь-яких дозах","Тільки при перевищенні дози в 10 разів"],a:1,ex:"Необоротна ototоксичність — пошкодження і загибель зовнішніх волоскових клітин органу Корті. Ризик факторів: висока доза, тривалий курс, поєднання з фуросемідом або ванкоміцином, вихідна ниркова недостатність."},
{type:"mcq",q:"Чому аміноглікозиди неефективні при анаеробних інфекціях?",o:["Анаероби мають стійкість через β-лактамази","Транспорт аміноглікозиду всередину бактерії потребує O2 (аеробний процес) — при анаеробозі не відбувається","Анаероби змінили 30S рибосому","Аміноглікозиди руйнуються в анаеробних умовах"],a:1,ex:"Транспорт аміноглікозидів через бактеріальну мембрану залежить від протонного градієнту та O2. В анаеробних умовах цей транспорт не функціонує → аміноглікозиди не потрапляють у клітину → неефективні."},
{type:"mcq",q:"Амікацин — найбільш стійкий до аміноглікозид-інактивуючих ферментів тому що:",o:["Менша молекула","Хімічні модифікації захищають від ферментів інактивації (ацетилтрансфераз, нуклеотидилтрансфераз, фосфотрансфераз)","Активніший транспорт у клітину","Більша концентрація в крові"],a:1,ex:"Амікацин — напівсинтетичний аміноглікозид з захисними хімічними модифікаціями, що роблять його резистентним до більшості ферментів, що інактивують інші аміноглікозиди (гентаміцин, тобраміцин)."}
]}
);

DRUGS.push(
// ════════ ПРОТИВІРУСНІ / ВІЛ ════════
{id:33,n:"Ацикловір",g:"Противірусні",grp:"Противогерпетичний (аналог нуклеозиду)",
mech:"Проліки. У вірус-інфікованих клітинах СПЕЦИФІЧНА вірусна тимідинкіназа (ТК) фосфорилює ацикловір → ацикловір-МФ → клітинні кінази → ацикловір-ТФ (активна форма). Ацикловір-ТФ: 1) конкурентно інгібує вірусну ДНК-полімеразу (афінітет до вірусної >> клітинної), 2) вбудовується в ланцюг вірусної ДНК як обривач → ланцюг ДНК не подовжується (облігатний обривач ланцюга — немає 3-OH групи).",
ind:"HSV-1 та HSV-2 (лабіальний, генітальний герпес, менінгоенцефаліт). Оперізуючий герпес (VZV). Вітряна віспа. Герпетичний кератит (очна мазь). Профілактика при імуносупресії.",
side:"Пероральний: нудота, головний біль (мінімальні). В/в: нефротоксичність (кристалурія!), нейротоксичність (галюцинації, судоми при нирковій недостатності), флебіт.",
contra:"Тяжка ниркова недостатність (необхідна корекція дози). Гіперчутливість.",
combo:"+ Ганцикловір неефективний проти ЦМВ (потрібен ганцикловір або валганцикловір). Синергізм з інтерфероном-α при важких герпетичних інфекціях.",
chain:["Ацикловір входить в інфіковану клітину","Вірусна тимідинкіназа (ТК) специфічно фосфорилює ацикловір → монофосфат","Клітинні кінази → дифосфат → ТРИФОСФАТ","Ацикловір-ТФ інгібує вірусну ДНК-полімеразу (афінітет у 100-1000 разів вищий ніж до клітинної)","Вбудовується в ДНК → ланцюг обривається","Реплікація вірусу зупиняється"],
tip:"Вибірковість через ВІРУСНУ тимідинкіназу. Нормальні клітини (без ТК вірусу) не активують ацикловір. Тому мінімальна токсичність. Ганцикловір — для ЦМВ (немає ТК герпесу).",
q:[
{type:"mcq",q:"Вибірковість дії ацикловіру зумовлена:",o:["Він не потрапляє в нормальні клітини","Лише вірусна тимідинкіназа (HSV/VZV) фосфорилює ацикловір до активної форми","Він швидше дифундує у вірус-інфіковані клітини","Вірусна ДНК-полімераза має інший розмір"],a:1,ex:"Ацикловір — проліки. Клітинна тимідинкіназа людини НЕ фосфорилює ацикловір (або дуже повільно). Лише вірусна ТК (HSV, VZV) активує його → ацикловір-ТФ → інгібування вірусної ДНК-полімерази. Нормальні клітини — захищені."},
{type:"mcq",q:"Ацикловір вбудовується в ДНК і обриває ланцюг тому що:",o:["Є занадто великим для подальшого добудовування","Не має 3-OH групи (необхідної для приєднання наступного нуклеотиду)","Денатурує ДНК","Блокує спіралізацію ДНК"],a:1,ex:"Ацикловір-ТФ — облігатний обривач ланцюга: у нього відсутня 3-OH группа → ДНК-полімераза не може приєднати наступний нуклеотид → ланцюг вірусної ДНК обривається."},
{type:"mcq",q:"Ацикловір НЕ ефективний при ЦМВ-інфекції тому що:",o:["ЦМВ резистентний до ацикловіру","ЦМВ не має вірусної тимідинкінази (або вона не фосфорилює ацикловір)","Ацикловір не проникає в клітини","ЦМВ знаходиться поза клітиною"],a:1,ex:"ЦМВ (цитомегаловірус) не має тимідинкінази, аналогічної HSV/VZV. Тому ацикловір фосфорилюється в ЦМВ-інфікованих клітинах дуже погано. Для ЦМВ — ганцикловір (активується протеїнкіназою UL97 ЦМВ)."},
{type:"mcq",q:"Профілактика нефротоксичності при в/в введенні ацикловіру:",o:["Призначення діуретиків","Достатня гідратація (попередньо в/в ФР) та повільне введення (>1 год)","Зниження дози вдвічі","Введення кожні 12 год замість 8 год"],a:1,ex:"Ацикловір кристалізується в канальцях нирок при концентрованій сечі. Профілактика: в/в 500 мл ФР перед кожним введенням, повільна інфузія (1 год). При ознаках ниркової недостатності — обов'язкова корекція дози."},
{type:"mcq",q:"Валацикловір відрізняється від ацикловіру:",o:["Різним механізмом дії","Проліками з вищою біодоступністю при пероральному прийомі (54% vs 15-30%)","Активний проти ЦМВ","Вводиться лише в/в"],a:1,ex:"Валацикловір = валін-естер ацикловіру. Після всмоктування в кишківнику → гідроліз в печінці → ацикловір. Біодоступність 54% vs 15-30% у ацикловіру. Зручніший (рідший прийом) при герпесі."}
]},

{id:34,n:"Ганцикловір",g:"Противірусні",grp:"Противогерпетичний / Анти-ЦМВ (аналог нуклеозиду)",
mech:"Аналог дезоксигуанозину. В ЦМВ-інфікованих клітинах фосфорилюється вірусною протеїнкіназою UL97 → ганцикловір-МФ → клітинні кінази → ганцикловір-ТФ. Ганцикловір-ТФ: інгібує вірусну ДНК-полімеразу ЦМВ, вбудовується в ДНК (облігатний обривач). Ефективніший проти ЦМВ, ніж ацикловір. Також активний проти HSV/VZV.",
ind:"ЦМВ-ретиніт при ВІЛ/СНІДі. ЦМВ-пневмонія, коліт, енцефаліт. Профілактика ЦМВ після трансплантації органів. Вроджена ЦМВ-інфекція.",
side:"Мієлосупресія (нейтропенія, тромбоцитопенія — головна!) — залежить від концентрації. Нефротоксичність. Гонадотоксичність (тератогенний і мутагенний). Нудота.",
contra:"Вагітність. Тяжка нейтропенія або тромбоцитопенія. ANC < 500/мкл.",
combo:"+ Фоскарнет при резистентному ЦМВ. Синергізм з АРТ (антиретровірусна терапія) при ВІЛ+ЦМВ.",
chain:["ЦМВ-протеїнкіназа UL97 фосфорилює ганцикловір (перший крок)","Клітинні кінази → ганцикловір-ТФ","Конкурентне інгібування ДНК-полімерази ЦМВ","Вбудовування в ДНК → обрив ланцюга","Загибель ЦМВ-інфікованих клітин"],
tip:"Головна відмінність від ацикловіру: активується UL97 ЦМВ (а не ТК герпесу). Мієлосупресія — обмежуючий побічний ефект. Контроль ОАК тижнево. Валганцикловір — пероральна проліки.",
q:[
{type:"mcq",q:"Ганцикловір відрізняється від ацикловіру тим, що:",o:["Має інший механізм блокади ДНК-полімерази","Активується вірусною протеїнкіназою UL97 ЦМВ (не тимідинкіназою HSV) → ефективний проти ЦМВ","Є природним нуклеозидом","Не є нуклеозидним аналогом"],a:1,ex:"Ключова відмінність: ацикловір фосфорилюється ТК HSV/VZV (не ЦМВ-UL97), ганцикловір — і ТК, і UL97. Тому ганцикловір активний проти ЦМВ, ацикловір — ні."},
{type:"mcq",q:"Головний обмежуючий побічний ефект ганцикловіру:",o:["Нефротоксичність","Мієлосупресія (нейтропенія, тромбоцитопенія)","Ototоксичність","Гепатотоксичність"],a:1,ex:"Мієлосупресія — дозозалежна. ANC < 500/мкл → зупинити терапію або знизити дозу. Моніторинг ОАК тричі на тиждень протягом перших 2 тижнів, потім щотижня."},
{type:"mcq",q:"Валганцикловір використовується замість ганцикловіру при:",o:["В/в монотерапії ЦМВ","Пероральному лікуванні (проліки ганцикловіру з вищою біодоступністю ~60%)","Резистентному ЦМВ","Профілактиці HSV"],a:1,ex:"Валганцикловір = L-валіловий естер ганцикловіру. Пероральна біодоступність ~60% (vs 5-9% у ганцикловіру). Після всмоктування → гідроліз → ганцикловір. Стандарт пероральної терапії ЦМВ."}
]},

{id:35,n:"Зидовудин (AZT)",g:"Противірусні/ВІЛ",grp:"НЗРТ — нуклеозидний інгібітор зворотної транскриптази",
mech:"Аналог тимідину. Після трифосфорилювання клітинними кіназами → зидовудин-ТФ. Механізм: 1) конкурентно інгібує ВІЛ-зворотну транскриптазу (афінітет до вірусного ферменту вищий, ніж до клітинної ДНК-полімерази), 2) вбудовується в ДНК як облігатний обривач (немає 3-OH). ВІЛ-зворотна транскриптаза перетворює вірусну РНК на ДНК — AZT блокує цей процес.",
ind:"ВІЛ-інфекція (у складі АРТ). Профілактика передачі ВІЛ від матері до дитини (найбільш доведений препарат). Постекспозиційна профілактика.",
side:"Мієлосупресія (анемія, нейтропенія). Міопатія (при тривалому прийомі). Гепатотоксичність. Лактатний ацидоз + стеатогепатит (клас-специфічний для НЗРТ).",
contra:"Тяжка анемія. Нейтропенія < 750/мкл. Серцева недостатність (рідко).",
combo:"Стандарт АРТ: 2 НЗРТ + 1 ІНАЗТ/ІП. Приклад: AZT + ламівудин (3TC) + нелфінавір. АРТ при вагітності для профілактики МТІТ.",
chain:["Клітинні кінази трифосфорилюють AZT","AZT-ТФ конкурує з природним dTTP","Вбудовується в ланцюг ДНК зворотної транскрипції","Відсутня 3-OH → ланцюг ДНК обривається","Вірусна ДНК не утворюється","Зниження вірусного навантаження"],
tip:"Перший АРВ препарат (1987). Профілактика МТІТ — AZT від 14 тижнів вагітності. Анемія — основний побічний ефект. Лактатний ацидоз — рідко, але смертельно.",
q:[
{type:"mcq",q:"Зидовудин (AZT) є:",o:["ННАЗТ (ненуклеозидний інгібітор ЗТ)","НЗРТ (нуклеозидний інгібітор зворотної транскриптази)","Інгібітором протеази","Інгібітором злиття"],a:1,ex:"НЗРТ (NRTI) — нуклеозидний (аналог тимідину) інгібітор зворотної транскриптази. Вбудовується в ДНК і обриває ланцюг. Клас: AZT, ламівудин, ставудин, тенофовір."},
{type:"mcq",q:"Головний побічний ефект AZT, що обмежує тривале застосування:",o:["Нефротоксичність","Мієлосупресія (анемія, нейтропенія)","Остеопороз","Кашель"],a:1,ex:"Мієлосупресія — анемія та нейтропенія. Механізм: AZT інгібує мітохондріальну ДНК-полімеразу γ → порушення синтезу мітохондріальної ДНК у клітинах кісткового мозку. Контроль ОАК кожні 3 місяці."},
{type:"mcq",q:"AZT є ключовим препаратом при:",o:["Гепатиті В","Профілактиці передачі ВІЛ від матері до дитини (МТІТ)","Туберкульозі","Криптококовому менінгіті"],a:1,ex:"AZT від 14 тижнів вагітності знижує ризик передачі ВІЛ від матері до дитини з ~25% до <2% при поєднанні з АРТ, кесаревим розтином та відмовою від грудного вигодовування."},
{type:"match",q:"Зіставте клас АРВ препаратів з представником та мішенню:",pairs:[["НЗРТ","AZT, ламівудин — зворотна транскриптаза (нуклеозиди)"],["ННАЗТ","Невірапін, єфавіренц — зворотна транскриптаза (ненуклеозиди)"],["ІП (інгібітори протеази)","Лопінавір, індинавір — ВІЛ-протеаза"],["ІЗ (інгібітори злиття)","Енфувіртид — злиття gp41 з мембраною"]],ex:"4 основні класи АРВ: НЗРТ, ННАЗТ, ІП, ІЗ (+ інгібітори інтегрази — ралтегравір). Стандарт АРТ: 2 НЗРТ + 1 інший клас."}
]},

{id:36,n:"Ламівудин (3TC)",g:"Противірусні/ВІЛ",grp:"НЗРТ (аналог цитидину)",
mech:"Аналог цитидину. Фосфорилюється → ламівудин-ТФ → інгібування зворотної транскриптази ВІЛ + обрив ланцюга. Унікально: активний також проти вірусу гепатиту В (ВГВ-ДНК-полімераза). Відносно низька токсичність порівняно з іншими НЗРТ.",
ind:"ВІЛ-інфекція (у складі АРТ — стандартний компонент). Хронічний гепатит В.",
side:"Мінімальні (один з найбільш переносимих НЗРТ). Нудота, діарея. Лактатний ацидоз (рідко, клас-специфічний).",
contra:"Гіперчутливість. Тяжка ниркова недостатність (корекція дози).",
combo:"Комбіна: AZT + 3TC = Комбівір. + Тенофовір при гепатиті В та ВІЛ.",
chain:["Фосфорилювання клітинними кіназами → 3TC-ТФ","Інгібування ЗТ ВІЛ (конкурентно з dCTP)","Вбудовування → обрив ланцюга","При гепатиті В → інгібування HBV-ДНК-полімерази"],
tip:"Комбівір = AZT + 3TC (1 таблетка 2 рази/добу). Активний і проти ВГВ — при ко-інфекції ВІЛ+ВГВ важливо! Резистентність — мутація M184V (розвивається швидко при монотерапії).",
q:[
{type:"mcq",q:"Унікальна перевага ламівудину (3TC) серед НЗРТ при ВІЛ:",o:["Найсильніший інгібітор ЗТ","Активний також проти вірусу гепатиту В","Перорально не потрібна активація","Найдовший T1/2"],a:1,ex:"Ламівудин інгібує ДНК-полімеразу вірусу гепатиту В (ВГВ). При ко-інфекції ВІЛ+ВГВ (часто) — ламівудин ефективно пригнічує обидва вірусу."},
{type:"mcq",q:"Комбівір — це:",o:["Ламівудин + індинавір","Зидовудин (AZT) + ламівудин (3TC)","Тенофовір + емтрицитабін","Невірапін + ставудин"],a:1,ex:"Комбівір = AZT 300 мг + 3TC 150 мг в одній таблетці. Зручна фіксована комбінація 2 НЗРТ для схем АРТ. Тривалий стандарт, зараз замінюється більш сучасними комбінаціями."}
]},

{id:37,n:"Тенофовір",g:"Противірусні/ВІЛ",grp:"НТЗРТ (нуклеотидний інгібітор ЗТ)",
mech:"Аналог аденозину монофосфату (нуклеотид, а не нуклеозид!). Потребує лише два фосфорилювання (не три) для активації. Інгібує зворотну транскриптазу ВІЛ та ДНК-полімеразу ВГВ. Менша мітохондріальна токсичність, ніж у НЗРТ (аналогів нуклеозидів). Тенофовір дизопроксил фумарат (ТДФ) — продукт.",
ind:"ВІЛ-інфекція (I лінія, стандарт сучасної АРТ). Хронічний гепатит В. Доконтактна профілактика ВІЛ (PrEP) у пар з ВІЛ+/ВІЛ-.",
side:"Нефротоксичність (синдром Фанконі — проксимальна тубулопатія). Зниження мінеральної щільності кісток. Лактатний ацидоз (рідше ніж НЗРТ).",
contra:"Тяжка ниркова недостатність (ШКФ<30). Гіперчутливість.",
combo:"Тенофовір + емтрицитабін = Трувада (PrEP стандарт). + Долутегравір + ламівудин = сучасна АРТ 1 лінії.",
chain:["Тенофовір ДФ (проліки) → тенофовір → АМФ (одне фосфорилювання) → АДФ","Ще одне фосфорилювання → тенофовір-ДФ (активна форма, аналог dATP)","Конкурентне інгібування ЗТ ВІЛ","Вбудовування → обрив ланцюга ДНК"],
tip:"Стандарт сучасної АРТ (разом з емтрицитабіном). PrEP (доконтактна профілактика) — Трувада. Контролювати функцію нирок (нефротоксичність) та щільність кісток.",
q:[
{type:"mcq",q:"Тенофовір відрізняється від AZT (нуклеозидний аналог) тим, що:",o:["Має той самий клас","Є нуклеотидним аналогом (NtRTI) — потребує лише 2 фосфорилювання замість 3","Більш токсичний","Не активний проти ВІЛ"],a:1,ex:"Тенофовір — нуклеотид (вже має один фосфат) → потребує лише 2 додаткових фосфорилювання для активації (vs 3 у НЗРТ). Менша мітохондріальна токсичність."},
{type:"mcq",q:"Трувада використовується для:",o:["Лікування туберкульозу","Доконтактної профілактики ВІЛ (PrEP) та АРТ","Лікування гепатиту C","Профілактики герпесу"],a:1,ex:"Трувада = тенофовір ДФ + емтрицитабін. PrEP (Pre-Exposure Prophylaxis) — ВІЛ-негативні особи з ризиком інфекції приймають щодня → ↓ ризик інфікування ВІЛ >90%."},
{type:"mcq",q:"Специфічний нирковий побічний ефект тенофовіру:",o:["Гломерулонефрит","Синдром Фанконі (проксимальна тубулопатія)","Ниркові камені","Анурія"],a:1,ex:"Тенофовір накопичується в проксимальних канальцях → мітохондріальна дисфункція → синдром Фанконі (гіпофосфатемія, гіпокаліємія, глюкозурія, амінокислотурія, протеїнурія). Контроль ШКФ та фосфату щоквартально."}
]},

{id:38,n:"Невірапін",g:"Противірусні/ВІЛ",grp:"ННАЗТ (ненуклеозидний інгібітор ЗТ)",
mech:"Ненуклеозидний — НЕ потребує фосфорилювання. Звʼязується з алостеричним сайтом («кишенею») зворотної транскриптази ВІЛ-1 → конформаційна зміна → зниження каталітичної активності. Не є конкурентним інгібітором. На відміну від НЗРТ — швидко розвивається резистентність (одна мутація K103N = висока резистентність).",
ind:"ВІЛ-1 (у складі АРТ). Профілактика МТІТ (одна доза матері + одна доза новонародженому).",
side:"Висип (до 50%), синдром Стівенса-Джонсона (рідко, небезпечно!). Гепатотоксичність (особливо при CD4>250 у жінок та CD4>400 у чоловіків!).",
contra:"CD4 > 250 у жінок та > 400 у чоловіків (підвищений ризик гепатотоксичності). Тяжке захворювання печінки.",
combo:"У складі АРТ: 2 НЗРТ + ННАЗТ. НЕ поєднувати з рифампіцином (індукція CYP3A4 → ↓ рівень невірапіну).",
chain:["Невірапін дифундує в ліпідну «кишеню» зворотної транскриптази","Конформаційна зміна → знижується рухливість ЗТ","Каталітична активність ЗТ різко падає","РНК → ДНК не відбувається","Реплікація ВІЛ-1 блокується"],
tip:"Специфічний для ВІЛ-1 (не ВІЛ-2). Висип та гепатотоксичність — серйозні ризики. МТІТ профілактика: невірапін одна доза матері при пологах + 72 год дитині — просто і ефективно у ресурс-обмежених умовах.",
q:[
{type:"mcq",q:"Невірапін відноситься до:",o:["НЗРТ","ННАЗТ (ненуклеозидний інгібітор ЗТ)","Інгібіторів протеази","Інгібіторів інтегрази"],a:1,ex:"ННАЗТ — ненуклеозидний. Не потребує фосфорилювання. Звʼязується з алостеричним сайтом ЗТ ВІЛ-1, але НЕ конкурує з нуклеотидами."},
{type:"mcq",q:"Невірапін неефективний при:",o:["ВІЛ-1","ВІЛ-2 (природна резистентність ННАЗТ)","Лікуванні без попередньої АРТ","Профілактиці МТІТ"],a:1,ex:"ННАЗТ (невірапін, єфавіренц) неефективні проти ВІЛ-2 — у ВІЛ-2 алостеричний сайт ЗТ відрізняється та не зв'язує ННАЗТ. ВІЛ-2 лікують НЗРТ + ІП."},
{type:"mcq",q:"Головний ризик гепатотоксичності від невірапіну підвищений у:",o:["Чоловіків з CD4 < 200","Жінок з CD4 > 250 та чоловіків з CD4 > 400 (парадоксально — кращий імунітет = вищий ризик)","Дітей до 2 років","Пацієнтів зі СНІДом (CD4 < 50)"],a:1,ex:"Парадокс: при вищому CD4 → більш активна імунна відповідь → імуноопосередкована гепатотоксичність від невірапіну. Тому у жінок з CD4>250 і чоловіків з CD4>400 — НЕ рекомендується невірапін."}
]},

// ════════ ГАСТРОЕНТЕРОЛОГІЯ ════════
{id:39,n:"Омепразол",g:"Гастроентерологія",grp:"Інгібітор протонної помпи (ІПП)",
mech:"Проліки (слабка основа). В кислому середовищі (pH<4) канальців парієтальних клітин → перетворення на сульфенамідну форму (активний) → ковалентне незворотнє звʼязування з SH-групами H+/K+-АТФази (протонної помпи) → необоротнє пригнічення секреції H+. Ефект зберігається 24-48 год (до синтезу нових молекул помпи). Активується лише в парієтальних клітинах (pH<4).",
ind:"Виразкова хвороба шлунка і 12-палої кишки. ГЕРХ. Синдром Золлінгера-Еллісона. Ерадикація H.pylori. Профілактика НПЗЗ-індукованої гастропатії. Кровотечі зі шлунка.",
side:"Головний біль. Діарея або закреп. Метеоризм. При тривалому прийомі: гіпомагніємія, дефіцит B12, C.difficile, гіпергастринемія, поліпи фундальних залоз.",
contra:"Гіперчутливість. Обережно з клопідогрелем (деякі ІПП знижують його ефективність через CYP2C19).",
combo:"+ Амоксицилін + кларитроміцин при H.pylori. Обережно + клопідогрель (особливо омепразол/езомепразол). Антациди можна одночасно (короткострокова симптоматика).",
chain:["Омепразол (слабка основа) → всмоктується в тонкому кишківнику (pH нейтральний)","Через кров → парієтальні клітини","Накопичується в канальцях (pH<2) → перетворення на сульфенамід","Ковалентне незворотнє звʼязування з SH-цистеїном H+/K+-АТФази","Помпа необоротньо заблокована","H+ не секретується → pH шлунка підвищується"],
tip:"ПЕРШИЙ ПРИЙОМ за 30 хв до їжі (помпи активні під час їжі). Незворотня дія — до 48 год. Всі ІПП мають однаковий механізм, але різний метаболізм (CYP2C19). Езомепразол = S-ізомер омепразолу.",
q:[
{type:"mcq",q:"Омепразол — це проліки тому що:",o:["Погано всмоктується в ШКТ","Активується лише в кислому середовищі парієтальних клітин (pH<4) → сульфенамід","Метаболізується в печінці до активного метаболіту","Потребує бактеріального ферменту"],a:1,ex:"При нейтральному pH (плазма, тонкий кишківник) омепразол стабільний. При pH<4 (канальці парієтальних клітин) → перетворення на сульфенамідну форму → ковалентне звʼязування з SH-групою H+/K+-АТФази."},
{type:"mcq",q:"Дія омепразолу є:",o:["Зворотньою (конкурентне інгібування)","Незворотньою (ковалентне звʼязування з H+/K+-АТФазою)","Тимчасовою (4-6 год)","Залежить від pH шлунка"],a:1,ex:"Незворотнє ковалентне звʼязування → ефект до 24-48 год (до синтезу нових молекул помпи). Тому ефективний при одноразовому прийомі на день, хоча T1/2 короткий (~1 год)."},
{type:"mcq",q:"Коли оптимально приймати омепразол?",o:["Після їжі","За 30 хвилин до їжі (натщесерце)","Безпосередньо під час їжі","Перед сном"],a:1,ex:"За 30 хв до їжі — проліки встигають потрапити в парієтальні клітини до активації помп їжею. Якщо приймати після їжі — більшість помп вже відпрацювала, блокування менш ефективне."},
{type:"mcq",q:"Різниця між омепразолом (ІПП) та фамотидином (H2-блокатор):",o:["Омепразол блокує H2-рецептор, фамотидин — протонну помпу","Омепразол незворотньо блокує H+/K+-АТФазу; фамотидин зворотньо блокує H2-рецептор гістаміну","Фамотидин ефективніший","Однаковий механізм"],a:1,ex:"ІПП (омепразол) > H2-блокатори (фамотидин) за ефективністю: ІПП блокують остаточний крок секреції (помпу), а H2-блокатори лише одну з трьох стимуляцій (гістамін). Тому ІПП знижують кислотність повніше."},
{type:"mcq",q:"Чому ІПП можуть знижувати ефект клопідогрелю?",o:["ІПП прямо антагонізують клопідогрель","Деякі ІПП (омепразол, езомепразол) інгібують CYP2C19 → знижений метаболізм проліків клопідогрелю → менше активного метаболіту → менший антиагрегантний ефект","ІПП підвищують тромбоцити","Взаємодії немає"],a:1,ex:"Клопідогрель — проліки, активуються CYP2C19. Омепразол та езомепразол — інгібітори CYP2C19 → менше активного клопідогрелю → знижена антиагрегантна активність → потенційно ↑ серцево-судинний ризик. Альтернатива: пантопразол (не інгібує CYP2C19)."},
{type:"mcq",q:"Яке ускладнення тривалого прийому ІПП повʼязане з дефіцитом вітаміну B12?",o:["Мегалобластна анемія та нейропатія","Залізодефіцитна анемія","Гіперхромна анемія","Гемолітична анемія"],a:0,ex:"B12 всмоктується після відщеплення від харчових білків кислотою шлунку та звʼязування з внутрішнім фактором. При знижені кислотності від ІПП → гірше відщеплення B12 від харчових білків → дефіцит B12 → мегалобластна анемія, фунікулярний мієлоз."}
]},

{id:40,n:"Фамотидин",g:"Гастроентерологія",grp:"Блокатор H2-гістамінових рецепторів",
mech:"Конкурентний зворотній антагоніст H2-рецепторів гістаміну в парієтальних клітинах → знижує базальну і стимульовану секрецію HCl. Ефективніший за ранітидин (II покоління H2-блокаторів). Значно слабший, ніж ІПП (блокує лише гістамінову стимуляцію, тоді як є ще гастринова та ацетилхолінова).",
ind:"Виразкова хвороба шлунка і 12-палої. ГЕРХ (легкі форми). Профілактика стресових виразок. Синдром Золлінгера-Еллісона (у низьких дозах).",
side:"Головний біль. Запаморочення. Зміни функції ЦНС (при тяжкій нирковій недостатності, частіше від циметидину). Гінекомастія (рідко — лише циметидин, фамотидин значно менше).",
contra:"Гіперчутливість. Тяжка ниркова недостатність (корекція дози).",
combo:"+ Антациди (симптоматичне полегшення). Не поєднувати з ІПП без необхідності (однакова мішень/ефект — кислота).",
chain:["Гістамін звʼязує H2-рецептор парієтальної клітини","Аденілатциклаза активується → цАМФ↑","H+/K+-АТФаза → секреція H+","Фамотидин: конкурентно блокує H2-рецептор","Зменшення цАМФ → менша активація помпи","Секреція HCl знижується (але не блокується повністю)"],
tip:"Конкурентне ЗВОРОТНЄ інгібування (vs незворотнє у ІПП). Ефект 8-12 год. Менш ефективний за ІПП — при тяжкому ГЕРХ та виразці переважають ІПП. Циметидин (I покоління) — більше взаємодій через CYP.",
q:[
{type:"mcq",q:"Фамотидин конкурентно блокує:",o:["H+/K+-АТФазу (протонну помпу)","H2-рецептори гістаміну в парієтальних клітинах","M3-холінорецептори","Гастринові рецептори"],a:1,ex:"H2-блокатор — конкурентний зворотній антагоніст H2-рецепторів. Блокує лише гістамін-опосередковану стимуляцію. ІПП блокують кінцевий крок (H+/K+-АТФазу) незворотньо."},
{type:"mcq",q:"Порівняно з омепразолом (ІПП), фамотидин (H2-блокатор):",o:["Ефективніший при ГЕРХ та виразці","Менш ефективний — блокує лише одну з трьох стимуляцій секреції HCl (гістамін, але не гастрин та АХ)","Однакової ефективності","Незворотньо блокує помпу"],a:1,ex:"H2-блокатори знижують секрецію кислоти менш повно: блокують лише гістамінову стимуляцію. Гастринова та холінергічна стимуляція помпи лишаються. ІПП блокують кінцевий крок — ефективніші."},
{type:"mcq",q:"Циметидин (I покоління H2-блокаторів) відрізняється від фамотидину (II покоління):",o:["Слабша антисекреторна дія і більше взаємодій (інгібітор CYP1A2, CYP2C9, CYP3A4)","Сильніший і безпечніший","Однакова безпека","Фамотидин — I покоління"],a:0,ex:"Циметидин: більш слабкий, потужний інгібітор CYP → багато взаємодій (варфарин, теофілін, диланзин, хінідин тощо). Фамотидин/ранітидин: менше взаємодій. Сучасний вибір — фамотидин або ніцатидин."}
]}
);
